import type { FlashcardData } from "./flashcards-rpn";

export const rnArrhythmiasChdAnticoagFlashcards: FlashcardData[] = [
  // ATRIAL FIBRILLATION — 25 cards
  { id: "rn-arr-afib-1", type: "question", question: "What is the hallmark ECG finding in atrial fibrillation?", options: ["Sawtooth P waves", "Absent P waves with irregularly irregular R-R intervals", "Prolonged PR interval", "Wide QRS complexes"], correctIndex: 1, answer: "Atrial fibrillation is characterized by absent organized P waves (replaced by fibrillatory waves) and irregularly irregular ventricular response. The atria fire chaotically at 350-600 impulses per minute.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-afib-2", type: "question", question: "A client with new-onset AFib has a CHA2DS2-VASc score of 3. What does the nurse anticipate?", options: ["Aspirin therapy only", "Oral anticoagulation with a DOAC or warfarin", "No anticoagulation needed", "Antiplatelet dual therapy"], correctIndex: 1, answer: "A CHA2DS2-VASc score ≥2 in men (≥3 in women) indicates high stroke risk requiring oral anticoagulation. DOACs are preferred over warfarin for non-valvular AFib.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-afib-3", type: "question", question: "What is the primary hemodynamic consequence of atrial fibrillation?", options: ["Increased preload", "Loss of atrial kick reducing cardiac output by 15-25%", "Increased SVR", "Enhanced coronary perfusion"], correctIndex: 1, answer: "Loss of coordinated atrial contraction (atrial kick) reduces ventricular filling and cardiac output by 15-25%. This is particularly significant in patients with diastolic dysfunction.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-afib-4", type: "question", question: "A hemodynamically stable client with AFib RVR (HR 156) is ordered IV diltiazem. What must the nurse assess first?", options: ["Blood glucose", "Blood pressure and presence of HFrEF", "Urine output", "Bowel sounds"], correctIndex: 1, answer: "Diltiazem has negative inotropic effects and is contraindicated in HFrEF. It can also cause significant hypotension. Assess baseline BP and cardiac function before administration.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-afib-5", type: "question", question: "Before elective cardioversion for AFib of unknown duration, what must be completed?", options: ["Chest X-ray", "TEE showing no thrombus or 3 weeks of therapeutic anticoagulation", "PFTs", "Cardiac catheterization"], correctIndex: 1, answer: "AFib >48 hours increases thrombus risk in the left atrial appendage. Either TEE must confirm no thrombus, or therapeutic anticoagulation for ≥3 weeks is required before cardioversion.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-afib-6", type: "question", question: "Which CHA2DS2-VASc component scores 2 points?", options: ["Hypertension", "Age 65-74", "Prior stroke or TIA", "Diabetes mellitus"], correctIndex: 2, answer: "Prior stroke/TIA/thromboembolism scores 2 points (the S2). Age ≥75 also scores 2. All other factors (CHF, HTN, Age 65-74, DM, Vascular disease, Sex category) score 1 point each.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-afib-7", type: "question", question: "A client on warfarin for AFib has INR 4.8 with no active bleeding. What action is anticipated?", options: ["Protamine sulfate", "Hold warfarin and administer oral vitamin K", "Continue same dose", "FFP immediately"], correctIndex: 1, answer: "INR 4.8 without bleeding: hold warfarin, give oral vitamin K 2.5-5 mg, recheck INR in 24 hours. FFP/PCC is reserved for active serious bleeding.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-afib-8", type: "question", question: "What differentiates rate control from rhythm control in AFib?", options: ["Rate control eliminates AFib", "Rate control slows ventricular rate; rhythm control restores sinus rhythm", "They are the same", "Rate control uses anticoagulants"], correctIndex: 1, answer: "Rate control (beta-blockers, CCBs, digoxin) accepts AFib but controls HR <110 bpm. Rhythm control (amiodarone, flecainide, cardioversion, ablation) attempts to restore and maintain NSR. Both require anticoagulation based on CHA2DS2-VASc.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-afib-9", type: "question", question: "A client with AFib becomes hemodynamically unstable (BP 72/40, AMS). What is the priority?", options: ["IV diltiazem bolus", "Immediate synchronized cardioversion", "IV amiodarone drip", "12-lead ECG and wait"], correctIndex: 1, answer: "Unstable AFib requires immediate synchronized cardioversion per ACLS. Synchronized mode prevents T-wave shock. Initial energy: 120-200J biphasic.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-afib-10", type: "question", question: "Which rate control agent is preferred for AFib with HFrEF?", options: ["Diltiazem", "Verapamil", "Metoprolol", "Nifedipine"], correctIndex: 2, answer: "Beta-blockers (metoprolol, carvedilol) are preferred for rate control in HFrEF. Non-dihydropyridine CCBs (diltiazem, verapamil) are contraindicated in HFrEF due to negative inotropy.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-afib-11", type: "question", question: "What is atrial remodeling in AFib?", options: ["Surgical atrial reconstruction", "Structural and electrical changes perpetuating AFib", "Normal post-cardioversion healing", "Valve replacement effect"], correctIndex: 1, answer: "Atrial remodeling (fibrosis, dilation, shortened refractory periods) makes AFib self-perpetuating. 'AFib begets AFib' — the longer it persists, the harder to convert.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-afib-12", type: "question", question: "What is the priority assessment before giving digoxin for AFib rate control?", options: ["Blood glucose", "Apical pulse for one full minute", "Urine output", "Bowel sounds"], correctIndex: 1, answer: "Assess apical pulse for one full minute. Hold if <60 bpm (adults). Monitor potassium — hypokalemia potentiates digoxin toxicity. Therapeutic level: 0.5-2.0 ng/mL.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-afib-13", type: "question", question: "What is the most serious complication of uncontrolled AFib?", options: ["Pneumonia", "Ischemic stroke from left atrial thrombus embolization", "Peptic ulcer", "UTI"], correctIndex: 1, answer: "Cardioembolic stroke from stagnant blood in the fibrillating left atrium (especially LA appendage). AFib increases stroke risk 5-fold. Anticoagulation is critical.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-afib-14", type: "question", question: "A client on apixaban for AFib missed two doses. What should the nurse advise?", options: ["Double dose immediately", "Take missed dose if within 6 hours of scheduled time", "Skip 48 hours then restart", "Go to the ED"], correctIndex: 1, answer: "For apixaban (BID dosing), take the missed dose if within 6 hours. If >6 hours, skip and resume at next scheduled time. Never double up.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-afib-15", type: "question", question: "What common symptom combination do clients with AFib most often report?", options: ["Jaw pain and diaphoresis", "Palpitations, fatigue, dizziness, exercise intolerance", "Productive cough and fever", "Bilateral leg swelling"], correctIndex: 1, answer: "Common AFib symptoms: palpitations, fatigue, dizziness, exercise intolerance, dyspnea. Some patients are asymptomatic and diagnosed incidentally.", category: "Arrhythmias & ECG", difficulty: 1 },
  { id: "rn-arr-afib-16", type: "question", question: "Why is the left atrial appendage (LAA) significant in AFib?", options: ["It generates P waves", "It is the most common site of thrombus formation in non-valvular AFib", "It regulates heart rate", "It produces aldosterone"], correctIndex: 1, answer: "The LAA is a trabeculated pouch where blood stasis occurs during AFib, forming >90% of thrombi in non-valvular AFib. LAA occlusion devices (Watchman) are an alternative to long-term anticoagulation.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-afib-17", type: "question", question: "What is the 'pill-in-the-pocket' approach for AFib?", options: ["Taking daily aspirin", "Self-administering a single dose of flecainide or propafenone at symptom onset for infrequent paroxysmal AFib", "Wearing a Holter monitor", "Taking digoxin daily"], correctIndex: 1, answer: "For select patients with infrequent paroxysmal AFib, a single oral dose of flecainide (200-300 mg) or propafenone (450-600 mg) can terminate episodes at home. Patient must first tolerate the drug under monitored conditions.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-afib-18", type: "question", question: "A client with AFib on warfarin has INR 2.5. Is this therapeutic?", options: ["No, INR is too high", "Yes, therapeutic INR for AFib is 2.0-3.0", "No, INR should be >4.0", "INR monitoring is not needed for warfarin"], correctIndex: 1, answer: "For most indications including AFib, therapeutic INR is 2.0-3.0. For mechanical mitral valves, the target is higher (2.5-3.5). INR 2.5 is within range.", category: "Arrhythmias & ECG", difficulty: 1 },
  { id: "rn-arr-afib-19", type: "question", question: "What is the significance of 'valvular' vs 'non-valvular' AFib for anticoagulation?", options: ["No significance", "Valvular AFib (mechanical valve or moderate-severe mitral stenosis) requires warfarin; DOACs are contraindicated", "Both types use the same medications", "Valvular AFib does not need anticoagulation"], correctIndex: 1, answer: "Valvular AFib (mechanical heart valve or moderate-severe mitral stenosis) requires warfarin specifically. DOACs (apixaban, rivaroxaban) are not approved for these patients due to increased thromboembolic risk.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-afib-20", type: "question", question: "How long should anticoagulation continue after successful cardioversion for AFib?", options: ["It can be stopped immediately", "At least 4 weeks post-cardioversion regardless of CHA2DS2-VASc score", "1 day post-cardioversion", "Only if symptoms persist"], correctIndex: 1, answer: "Anticoagulation must continue for at least 4 weeks after cardioversion because atrial mechanical function may not fully recover (atrial stunning), allowing thrombus formation even after rhythm restoration.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-afib-21", type: "question", question: "What is the role of catheter ablation in AFib management?", options: ["It replaces the need for all medications", "Pulmonary vein isolation destroys triggers for AFib; indicated when medications fail or as first-line in select patients", "It is experimental and not recommended", "It cures all forms of AFib permanently"], correctIndex: 1, answer: "Catheter ablation (pulmonary vein isolation) targets ectopic foci originating from the pulmonary veins that trigger AFib. Success rates are 60-80% for paroxysmal AFib. Multiple procedures may be needed.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-afib-22", type: "question", question: "A client develops AFib during acute illness (sepsis). What is this called?", options: ["Permanent AFib", "New-onset AFib secondary to an acute precipitant — may resolve when the underlying cause is treated", "Chronic AFib", "Lone AFib"], correctIndex: 1, answer: "AFib triggered by acute illness (sepsis, surgery, PE, thyrotoxicosis) may resolve once the precipitant is treated. Anticoagulation decisions still follow CHA2DS2-VASc. Long-term rhythm drugs may not be needed if the trigger is eliminated.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-afib-23", type: "question", question: "What thyroid condition can precipitate atrial fibrillation?", options: ["Hypothyroidism", "Hyperthyroidism (thyrotoxicosis)", "Thyroid cancer", "Hashimoto's disease"], correctIndex: 1, answer: "Hyperthyroidism increases cardiac sensitivity to catecholamines and shortens atrial refractory periods, triggering AFib in up to 15% of patients. All new AFib patients should have TSH checked.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-afib-24", type: "question", question: "Why should the nurse monitor potassium levels in a client with AFib on digoxin and furosemide?", options: ["Potassium has no effect on digoxin", "Furosemide causes hypokalemia which potentiates digoxin toxicity — risk of fatal arrhythmias", "Furosemide increases potassium", "Digoxin raises potassium levels"], correctIndex: 1, answer: "Loop diuretics (furosemide) cause potassium wasting. Hypokalemia enhances digoxin binding to sodium-potassium ATPase, potentiating toxicity (visual changes, bradycardia, nausea, fatal arrhythmias). Monitor K+ and replace as needed.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-afib-25", type: "question", question: "What is the HAS-BLED score used for in AFib management?", options: ["Determines stroke risk", "Assesses bleeding risk to weigh against anticoagulation benefit", "Measures heart failure severity", "Guides cardioversion timing"], correctIndex: 1, answer: "HAS-BLED estimates bleeding risk (Hypertension, Abnormal renal/liver function, Stroke, Bleeding history, Labile INR, Elderly, Drugs/alcohol). High score doesn't contraindicate anticoagulation but identifies modifiable risk factors to address.", category: "Arrhythmias & ECG", difficulty: 3 },

  // ATRIAL FLUTTER — 25 cards
  { id: "rn-arr-aflutter-1", type: "question", question: "What is the characteristic ECG pattern of atrial flutter?", options: ["Absent P waves", "Sawtooth flutter (F) waves best seen in leads II, III, aVF", "Delta waves", "ST elevation"], correctIndex: 1, answer: "Atrial flutter produces characteristic sawtooth flutter (F) waves at ~300 bpm, best seen in inferior leads (II, III, aVF). Ventricular rate depends on conduction ratio.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-aflutter-2", type: "question", question: "What is the typical atrial rate in atrial flutter?", options: ["60-100 bpm", "150-180 bpm", "250-350 bpm (~300 bpm)", "400-600 bpm"], correctIndex: 2, answer: "Typical atrial flutter has atrial rate ~300 bpm from a single macro-reentrant circuit around the tricuspid valve annulus. AV node provides physiologic block (2:1, 3:1, 4:1).", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-aflutter-3", type: "question", question: "A regular narrow-complex tachycardia at exactly 150 bpm with no visible P waves. What should the nurse suspect?", options: ["Sinus tachycardia", "Atrial flutter with 2:1 conduction", "VTach", "Third-degree block"], correctIndex: 1, answer: "Regular narrow-complex tachycardia at exactly 150 bpm should always raise suspicion for atrial flutter with 2:1 conduction (300/2=150). Flutter waves may be hidden in T waves. Adenosine can unmask them.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-aflutter-4", type: "question", question: "What is the definitive treatment for typical atrial flutter?", options: ["Lifelong beta-blocker", "Catheter ablation of the cavotricuspid isthmus (CTI)", "Permanent pacemaker", "Heart transplant"], correctIndex: 1, answer: "CTI ablation for typical atrial flutter has success rates >95%. The CTI is the critical component of the reentrant circuit. Ablation creates a conduction block line.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-aflutter-5", type: "question", question: "How does adenosine help diagnose atrial flutter?", options: ["Converts flutter permanently", "Transiently blocks AV conduction to unmask hidden flutter waves", "Increases atrial rate", "No diagnostic use"], correctIndex: 1, answer: "Adenosine transiently blocks AV conduction, slowing ventricular rate to unmask underlying sawtooth flutter waves hidden in QRS/T waves. Diagnostic maneuver only — does not terminate flutter.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-aflutter-6", type: "question", question: "Does atrial flutter carry stroke risk similar to AFib?", options: ["No stroke risk", "Yes, same CHA2DS2-VASc guidelines apply", "Higher than AFib", "Only with diabetes"], correctIndex: 1, answer: "Atrial flutter carries similar stroke risk to AFib. Same CHA2DS2-VASc scoring and anticoagulation thresholds apply. Many patients alternate between flutter and fibrillation.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-aflutter-7", type: "question", question: "Why is flecainide alone dangerous for atrial flutter?", options: ["No concern", "Can slow atrial rate to allow 1:1 AV conduction causing ventricular rates >200 bpm", "Causes renal failure", "Only for VTach"], correctIndex: 1, answer: "Class IC drugs (flecainide, propafenone) alone can slow atrial rate enough for 1:1 AV conduction, causing dangerous ventricular rates. Must always pair with an AV nodal blocking agent.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-aflutter-8", type: "question", question: "Atrial flutter with variable conduction ratios (2:1 alternating with 4:1) appears how on the monitor?", options: ["Regular at 150 bpm", "Irregular ventricular rhythm that can mimic AFib", "Wide complex tachycardia", "Normal sinus"], correctIndex: 1, answer: "Variable conduction ratios produce irregular R-R intervals mimicking AFib. The key distinction is regular, organized flutter waves at ~300 bpm between QRS complexes.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-aflutter-9", type: "question", question: "What initial cardioversion energy is typical for atrial flutter?", options: ["360 J", "50-100 J biphasic (lower than AFib)", "200-300 J", "10 J"], correctIndex: 1, answer: "Atrial flutter converts at lower energy (50-100J biphasic) than AFib because it involves a single organized reentrant circuit rather than multiple chaotic wavelets.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-aflutter-10", type: "question", question: "What is the mechanism of typical atrial flutter?", options: ["Multiple ectopic foci", "Single macro-reentrant circuit counterclockwise around the tricuspid valve annulus through the CTI", "Delayed afterdepolarizations", "SA node automaticity"], correctIndex: 1, answer: "Typical (counterclockwise) flutter involves a single macro-reentrant circuit traveling around the tricuspid valve annulus through the cavotricuspid isthmus, producing regular sawtooth waves at ~300 bpm.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-aflutter-11", type: "question", question: "A client with atrial flutter converts to AFib after rate control medication. Is this a treatment failure?", options: ["Yes, it means the medication is wrong", "No, coexistence of flutter and AFib is common; many patients alternate between both rhythms", "This never happens", "It indicates medication allergy"], correctIndex: 1, answer: "Flutter and AFib frequently coexist. Many patients alternate between both rhythms. Conversion from flutter to AFib (or vice versa) is clinically common and does not necessarily indicate treatment failure.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-aflutter-12", type: "question", question: "What is atypical atrial flutter?", options: ["Same as typical flutter", "Flutter circuit that does NOT use the CTI — involves other atrial structures, often left atrium, and is more difficult to ablate", "Flutter with bradycardia", "Flutter in children only"], correctIndex: 1, answer: "Atypical flutter uses circuits outside the CTI (often left atrium or around surgical scars). It does not respond to CTI ablation and requires more complex mapping and ablation strategies. Success rates are lower.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-aflutter-13", type: "question", question: "Post-cardiac surgery, a client develops a regular atrial tachycardia at 250 bpm. What should the nurse consider?", options: ["Normal recovery", "Post-surgical (incisional) atrial flutter — a common complication due to reentry around surgical scar lines", "Ventricular tachycardia", "Equipment malfunction"], correctIndex: 1, answer: "Incisional atrial flutter is common after cardiac surgery (especially atrial procedures). Surgical scars create barriers around which reentrant circuits form. Treatment includes antiarrhythmics and potentially catheter ablation.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-aflutter-14", type: "question", question: "What is ibutilide and when is it used for atrial flutter?", options: ["A beta-blocker for rate control", "An IV class III antiarrhythmic used for pharmacologic cardioversion of recent-onset flutter", "An anticoagulant", "A calcium channel blocker"], correctIndex: 1, answer: "Ibutilide (Corvert) is an IV class III antiarrhythmic that prolongs repolarization. It is effective for acute pharmacologic cardioversion of flutter (more effective for flutter than AFib). Monitor for QT prolongation and Torsades risk.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-aflutter-15", type: "question", question: "A client on dofetilide for flutter must have what monitored?", options: ["Blood glucose", "QTc interval and renal function — dose adjustments based on creatinine clearance", "Liver enzymes only", "Hemoglobin"], correctIndex: 1, answer: "Dofetilide requires QTc monitoring (hold if QTc >500 ms) and dose adjustment by creatinine clearance. FDA mandates initiation in a hospital setting with continuous telemetry for ≥3 days.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-aflutter-16", type: "question", question: "What is the ventricular rate with atrial flutter at 3:1 conduction?", options: ["300 bpm", "150 bpm", "100 bpm", "75 bpm"], correctIndex: 2, answer: "With atrial rate of 300 bpm and 3:1 AV block, the ventricular rate is 300/3 = 100 bpm. Common conduction ratios: 2:1 = 150, 3:1 = 100, 4:1 = 75 bpm.", category: "Arrhythmias & ECG", difficulty: 1 },
  { id: "rn-arr-aflutter-17", type: "question", question: "What teaching should the nurse provide to a patient post-CTI ablation?", options: ["Avoid all exercise forever", "Avoid strenuous activity for 48 hours, monitor access site for bleeding, and attend follow-up appointments", "No follow-up needed since cure rate is high", "Start aspirin indefinitely"], correctIndex: 1, answer: "Post-ablation teaching: monitor femoral access site for bleeding/hematoma, restrict strenuous activity 48 hours, report palpitations/dizziness (recurrence), attend follow-up. Anticoagulation may continue temporarily per provider.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-aflutter-18", type: "question", question: "How does the nurse distinguish atrial flutter from sinus tachycardia on ECG?", options: ["They look identical", "Flutter has sawtooth F waves with no isoelectric baseline between waves; sinus tach has normal P waves before each QRS", "Flutter is always faster", "Sinus tach has wider QRS"], correctIndex: 1, answer: "Atrial flutter: sawtooth F waves at ~300 bpm with no true isoelectric baseline between waves. Sinus tachycardia: visible upright P waves (in lead II) preceding each QRS with an isoelectric baseline. Rate overlap can occur.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-aflutter-19", type: "question", question: "A client with atrial flutter on IV diltiazem develops hypotension (BP 82/50). What should the nurse do?", options: ["Increase the diltiazem rate", "Stop the infusion, place client supine, notify provider, prepare IV calcium gluconate and fluids", "Give more diltiazem", "Wait for BP to improve"], correctIndex: 1, answer: "Hypotension from IV diltiazem: stop infusion, position supine, IV NS bolus, notify provider. IV calcium gluconate can reverse CCB-mediated vasodilation and negative inotropy. Monitor closely.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-aflutter-20", type: "question", question: "What risk factor is most commonly associated with atrial flutter development?", options: ["Diabetes alone", "Structural heart disease, particularly right atrial enlargement", "Vitamin D deficiency", "Anemia"], correctIndex: 1, answer: "Atrial flutter is most commonly associated with structural heart disease: right atrial enlargement (from COPD, tricuspid disease, PE, ASD), post-cardiac surgery, prior MI, and heart failure.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-aflutter-21", type: "question", question: "Can atrial flutter occur with 1:1 conduction in healthy AV nodes?", options: ["Yes, commonly", "No — 1:1 conduction typically occurs with sympathetic stimulation, vagolysis, or class IC drugs without AV blocking agents", "Only in children", "Only in elderly"], correctIndex: 1, answer: "1:1 conduction is uncommon with normal AV nodes at rest but can occur with enhanced AV conduction (exercise, sympathetic surge, fever) or when class IC drugs slow atrial rate enough for the AV node to conduct every impulse.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-aflutter-22", type: "question", question: "What is the role of amiodarone in atrial flutter management?", options: ["First-line treatment", "Can be used for rate control and chemical cardioversion but is not first-line; CTI ablation is preferred for typical flutter", "Contraindicated in flutter", "Used only for AV nodal reentry"], correctIndex: 1, answer: "Amiodarone has both rate-controlling and rhythm-controlling properties for flutter but is not first-line due to side effects. CTI ablation is preferred for typical flutter given its high success rate and low complication rate.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-aflutter-23", type: "question", question: "A client with flutter has 4:1 conduction and HR 75. They feel fine. Does this require treatment?", options: ["Always needs immediate cardioversion", "Rate-controlled flutter with acceptable HR may be managed conservatively with anticoagulation based on CHA2DS2-VASc", "No treatment ever needed", "Requires pacemaker"], correctIndex: 1, answer: "Rate-controlled flutter (HR 75 with 4:1 block) with no symptoms can be managed with anticoagulation and monitoring. Catheter ablation may be offered for definitive cure. Rate control alone is an acceptable strategy.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-aflutter-24", type: "question", question: "What complication should the nurse watch for after cardioversion of atrial flutter?", options: ["Hyperglycemia", "Thromboembolism (stroke) from dislodged atrial thrombus", "Hyperthermia", "Renal failure"], correctIndex: 1, answer: "Post-cardioversion thromboembolic events (stroke, systemic embolism) can occur from thrombus dislodgement. This is why pre-cardioversion anticoagulation or TEE is mandatory. Continue anticoagulation for ≥4 weeks post-cardioversion.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-aflutter-25", type: "question", question: "What is the nurse's role during electrical cardioversion for flutter?", options: ["Administer the shock", "Ensure proper sedation, confirm synchronized mode, clear the patient, monitor airway/breathing post-procedure", "Leave the room", "Only monitor BP afterward"], correctIndex: 1, answer: "Nursing role: verify informed consent, ensure IV access, confirm sedation (propofol/etomidate/midazolam), verify synchronized mode on defibrillator, clear patient and staff before shock, suction/airway equipment at bedside, monitor post-procedure.", category: "Arrhythmias & ECG", difficulty: 2 },

  // SVT — 25 cards
  { id: "rn-arr-svt-1", type: "question", question: "What is the first intervention for stable SVT?", options: ["Defibrillation", "Vagal maneuvers (modified Valsalva or carotid sinus massage)", "IV amiodarone", "Intubation"], correctIndex: 1, answer: "For stable SVT, vagal maneuvers are first-line. Modified Valsalva (bear down 15 seconds then supine with legs elevated) increases parasympathetic tone and may terminate reentrant SVT.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-svt-2", type: "question", question: "How should IV adenosine be administered for SVT?", options: ["Slow push over 5 minutes", "Rapid IV push 1-2 seconds via antecubital IV followed by 20 mL NS rapid flush", "Mixed in 100 mL NS drip", "IM injection"], correctIndex: 1, answer: "Adenosine half-life <10 seconds — must be rapid IV push (1-2 sec) through large-bore proximal IV (antecubital), immediately followed by 20 mL NS rapid flush. Initial dose: 6 mg, then 12 mg if needed.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-svt-3", type: "question", question: "What is the most common mechanism of paroxysmal SVT?", options: ["SA node dysfunction", "AV nodal reentrant tachycardia (AVNRT)", "Ventricular ectopy", "Flutter with variable block"], correctIndex: 1, answer: "AVNRT accounts for ~60% of paroxysmal SVT. It involves dual pathways within or near the AV node (slow and fast). Impulse typically travels down slow and up fast pathway at 150-250 bpm.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-svt-4", type: "question", question: "A client with WPW develops AFib. Which medications are contraindicated?", options: ["Procainamide", "AV nodal blockers (diltiazem, verapamil, digoxin, adenosine)", "Amiodarone", "Ibutilide"], correctIndex: 1, answer: "In WPW with AFib, AV nodal blockers are ABSOLUTELY CONTRAINDICATED — they block AV node but allow unopposed rapid accessory pathway conduction, potentially causing VFib and death. Use procainamide or cardioversion.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-svt-5", type: "question", question: "What should the nurse warn the patient about before adenosine?", options: ["Severe headache lasting hours", "Brief chest tightness, flushing, feeling of impending doom lasting seconds", "Permanent hearing loss", "Prolonged hypotension"], correctIndex: 1, answer: "Adenosine commonly causes brief (5-10 sec) chest tightness, flushing, dyspnea, sense of impending doom as it causes transient AV block. Warn patients beforehand. Effects are transient due to ultra-short half-life.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-svt-6", type: "question", question: "What is the ECG hallmark of WPW syndrome?", options: ["Prolonged QT", "Delta wave, short PR (<0.12 sec), wide QRS (>0.12 sec)", "Sawtooth waves", "ST depression V1-V4"], correctIndex: 1, answer: "WPW: delta wave (slurred QRS upstroke), short PR (<0.12 sec), wide QRS (>0.12 sec) from pre-excitation of the ventricle through an accessory pathway (Bundle of Kent) bypassing the AV node.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-svt-7", type: "question", question: "A client on dipyridamole has SVT. How does this affect adenosine dosing?", options: ["No interaction", "Dipyridamole potentiates adenosine — reduce initial dose to 3 mg instead of 6 mg", "Neutralizes adenosine", "Cannot give adenosine at all"], correctIndex: 1, answer: "Dipyridamole inhibits adenosine reuptake, significantly potentiating effects. Reduce dose (3 mg instead of 6 mg). Conversely, theophylline/caffeine are adenosine antagonists and may reduce effectiveness.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-svt-8", type: "question", question: "What distinguishes SVT from sinus tachycardia?", options: ["SVT always has wide QRS", "SVT has abrupt onset/offset at 150-250 bpm; sinus tach has gradual onset/offset with visible P waves", "They are identical", "Sinus tach is always faster"], correctIndex: 1, answer: "SVT: abrupt (paroxysmal) onset/termination, rate 150-250, P waves often buried. Sinus tach: gradual onset/offset, visible P waves, rate usually 100-150, responds to underlying cause.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-svt-9", type: "question", question: "What is the modified Valsalva maneuver technique?", options: ["Cough forcefully", "Bear down/strain for 15 seconds in a semi-recumbent position, then lie supine with legs elevated 45 degrees", "Hold breath indefinitely", "Deep breathing exercises"], correctIndex: 1, answer: "Modified Valsalva: strain for 15 seconds, then lie flat with legs elevated 45° for 15 seconds. The postural modification increases venous return and enhances vagal response. Success rates are higher than standard Valsalva.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-svt-10", type: "question", question: "What is AVRT and how does it differ from AVNRT?", options: ["They are the same", "AVRT uses an accessory pathway (WPW) between atria and ventricles; AVNRT uses dual pathways within the AV node", "AVRT is a ventricular arrhythmia", "AVNRT requires an accessory pathway"], correctIndex: 1, answer: "AVRT (AV reentrant tachycardia) uses an accessory pathway (e.g., Bundle of Kent in WPW) as one limb of the circuit. AVNRT uses dual pathways (slow and fast) within the AV node itself. Both are narrow-complex SVT but have different treatment implications.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-svt-11", type: "question", question: "What is the second-line treatment if adenosine fails for SVT?", options: ["Defibrillation", "IV diltiazem or IV beta-blocker (metoprolol)", "IV amiodarone", "Oral digoxin"], correctIndex: 1, answer: "If adenosine fails (2 doses of 12 mg), IV diltiazem (0.25 mg/kg) or IV metoprolol (5 mg) can be used for hemodynamically stable SVT. If unstable at any point, proceed to synchronized cardioversion.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-svt-12", type: "question", question: "Why should carotid sinus massage NOT be performed on a client with a carotid bruit?", options: ["It will not work", "Risk of dislodging carotid plaque causing stroke", "It will increase heart rate", "Carotid bruits are normal findings"], correctIndex: 1, answer: "Carotid bruit suggests carotid atherosclerotic plaque. Massage could dislodge plaque causing carotid embolism and stroke. Contraindications also include: known carotid stenosis, recent stroke/TIA, and elderly patients with known atherosclerosis.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-svt-13", type: "question", question: "A child presents with SVT (HR 260). What is the first vagal maneuver to try in a young child?", options: ["Carotid massage", "Apply ice-cold wet cloth to the face (diving reflex)", "Valsalva maneuver", "Eyeball pressure"], correctIndex: 1, answer: "In infants and young children, the diving reflex is the most effective vagal maneuver: apply an ice-cold wet cloth over the eyes and bridge of nose for 15-20 seconds. This triggers a powerful vagal response. Valsalva and carotid massage are difficult in young children.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-svt-14", type: "question", question: "When is catheter ablation indicated for SVT?", options: ["First episode only", "Recurrent symptomatic SVT, failed or intolerant of medical therapy, or patient preference for definitive cure", "Only if AFib develops", "Never indicated"], correctIndex: 1, answer: "Catheter ablation is indicated for recurrent SVT causing symptoms, medication intolerance/failure, or patient preference. Success rates >95% for AVNRT and AVRT. It is a curative procedure for most SVT mechanisms.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-svt-15", type: "question", question: "What happens if adenosine is given to a client with atrial flutter or AFib?", options: ["It will cure the arrhythmia", "Adenosine will transiently slow AV conduction, unmasking the underlying atrial rhythm, but will NOT terminate flutter or AFib", "It will worsen to VFib", "No effect at all"], correctIndex: 1, answer: "Adenosine terminates reentrant SVT involving the AV node (AVNRT, AVRT) but does NOT terminate atrial flutter or AFib. It can be diagnostically useful: transient AV block unmasks underlying flutter/AFib waves.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-svt-16", type: "question", question: "A pregnant woman develops SVT. What special considerations apply?", options: ["All SVT treatments are safe in pregnancy", "Adenosine is safe in pregnancy; avoid metoprolol in first trimester; cardioversion is safe if unstable", "SVT cannot occur in pregnancy", "Only cesarean delivery can treat SVT"], correctIndex: 1, answer: "Adenosine is considered safe in pregnancy (doesn't cross placenta significantly). Beta-blockers (metoprolol) can be used with monitoring. Cardioversion is safe at all stages if hemodynamically unstable. Avoid atenolol (fetal growth restriction).", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-svt-17", type: "question", question: "What is the typical heart rate range for SVT?", options: ["60-100 bpm", "100-150 bpm", "150-250 bpm", "300-400 bpm"], correctIndex: 2, answer: "SVT typically produces rates of 150-250 bpm with narrow QRS complexes. The abrupt onset and regular, rapid rate distinguishes it from sinus tachycardia (gradual onset, usually <150 bpm).", category: "Arrhythmias & ECG", difficulty: 1 },
  { id: "rn-arr-svt-18", type: "question", question: "What is the significance of 'pseudo-R wave in V1' on ECG during SVT?", options: ["Normal finding", "Suggests AVNRT — retrograde P waves buried in the QRS create a pseudo-R' deflection in V1", "Indicates STEMI", "Artifact"], correctIndex: 1, answer: "In typical AVNRT, retrograde P waves occur simultaneously with QRS (or immediately after), creating a 'pseudo-R prime' in V1 and 'pseudo-S wave' in inferior leads. This helps identify AVNRT as the SVT mechanism.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-svt-19", type: "question", question: "What is the correct adenosine dose sequence for SVT?", options: ["6 mg, then 6 mg, then 6 mg", "6 mg, then 12 mg, then 12 mg if needed", "12 mg, then 24 mg", "3 mg only"], correctIndex: 1, answer: "Adenosine dosing: initial 6 mg rapid IV push. If no effect in 1-2 minutes, give 12 mg. A second 12 mg dose can be given if needed. Maximum: 12 mg per dose (some protocols allow 18 mg for very large patients).", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-svt-20", type: "question", question: "What monitoring is essential during and immediately after adenosine administration?", options: ["Blood glucose", "Continuous ECG rhythm strip recording — to capture the moment of rhythm conversion for diagnostic purposes", "Urine output", "Pupil checks"], correctIndex: 1, answer: "Run a continuous rhythm strip during adenosine to capture the response: the transient AV block and any underlying rhythm revealed (flutter waves, AFib) aids diagnosis. Also monitor for prolonged pauses, hypotension, and bronchospasm.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-svt-21", type: "question", question: "Why is adenosine relatively contraindicated in asthma?", options: ["It increases heart rate", "Adenosine can trigger bronchospasm in asthmatics by stimulating A1 receptors on bronchial smooth muscle", "It causes hyperglycemia in asthmatics", "No contraindication exists"], correctIndex: 1, answer: "Adenosine can trigger significant bronchospasm through A1 receptor stimulation on bronchial smooth muscle. Use with extreme caution in asthma. IV diltiazem or beta-blockers (with caution) are alternatives. Avoid in severe asthma.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-svt-22", type: "question", question: "A client's SVT converts after adenosine but recurs 20 minutes later. What does this suggest?", options: ["Adenosine failed", "The underlying substrate (dual AV node pathways or accessory pathway) still exists — recurrence is expected until definitive ablation", "Adenosine was given too fast", "The client is allergic to adenosine"], correctIndex: 1, answer: "Adenosine terminates the current episode but does not eliminate the substrate. SVT recurrence is expected because the reentrant pathway persists. For recurrent SVT, options include: long-term oral agents (CCB, beta-blocker, flecainide) or catheter ablation for cure.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-svt-23", type: "question", question: "What energy level is used for synchronized cardioversion of unstable SVT?", options: ["360 J", "50-100 J biphasic initially", "200 J", "5 J"], correctIndex: 1, answer: "Synchronized cardioversion for SVT begins at 50-100 J biphasic. Always confirm synchronized mode is activated. Increase energy with subsequent attempts if initial shock is unsuccessful.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-svt-24", type: "question", question: "What oral medication is commonly prescribed for SVT prevention in patients who decline ablation?", options: ["Warfarin", "Oral diltiazem, metoprolol, or flecainide for ongoing rate/rhythm control", "Aspirin", "Lisinopril"], correctIndex: 1, answer: "For SVT prevention: beta-blockers (metoprolol) or CCBs (diltiazem/verapamil) are first-line. Flecainide or propafenone can be used if these fail (with AV nodal blocker). Catheter ablation remains the definitive cure.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-svt-25", type: "question", question: "What is the nurse's priority when SVT does not terminate with vagal maneuvers or adenosine and the client becomes unstable?", options: ["Try more adenosine", "Immediate synchronized cardioversion — do not delay", "Start IV antibiotics", "Obtain chest X-ray"], correctIndex: 1, answer: "If pharmacologic measures fail and the client becomes hemodynamically unstable (hypotension, AMS, chest pain, acute HF), proceed immediately to synchronized cardioversion. Do not delay for additional medication trials.", category: "Arrhythmias & ECG", difficulty: 2 },

  // VENTRICULAR TACHYCARDIA — 25 cards
  { id: "rn-arr-vtach-1", type: "question", question: "What defines VTach on ECG?", options: ["Narrow QRS with regular rhythm", "Wide QRS (>0.12 sec) at 100-250 bpm with ≥3 consecutive ventricular beats", "Absent P waves with irregular rhythm", "Normal P waves with prolonged PR"], correctIndex: 1, answer: "VTach: ≥3 consecutive PVCs at >100 bpm with wide QRS (>0.12 sec). Originates below the bundle of His, producing abnormal depolarization pattern.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-vtach-2", type: "question", question: "Pulseless VTach: what is the immediate intervention?", options: ["Atropine 1 mg IV", "Defibrillation (unsynchronized) and CPR", "Vagal maneuvers", "IV diltiazem"], correctIndex: 1, answer: "Pulseless VTach = cardiac arrest rhythm, treated like VFib: immediate defibrillation, CPR, epinephrine q3-5min, amiodarone 300 mg then 150 mg.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-vtach-3", type: "question", question: "Sustained vs non-sustained VTach: what is the distinction?", options: ["Sustained has wider QRS", "Sustained lasts ≥30 seconds or causes hemodynamic instability; NSVT <30 seconds and self-terminates", "NSVT is more dangerous", "No difference"], correctIndex: 1, answer: "Sustained VTach: ≥30 seconds OR causes hemodynamic compromise requiring intervention. NSVT: ≥3 PVCs lasting <30 seconds, self-terminates. Sustained is a medical emergency.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-vtach-4", type: "question", question: "Stable sustained monomorphic VTach with a pulse: what is the priority drug?", options: ["Defibrillation max energy", "IV amiodarone 150 mg over 10 minutes", "Vagal maneuvers", "Transcutaneous pacing"], correctIndex: 1, answer: "Hemodynamically stable VTach with pulse: IV amiodarone 150 mg over 10 min is first-line. If unstable at any point, proceed to synchronized cardioversion. Have defibrillator at bedside.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-vtach-5", type: "question", question: "What distinguishes Torsades de Pointes from monomorphic VTach?", options: ["Torsades is narrow complex", "Torsades shows QRS axis twisting around baseline associated with prolonged QT", "Monomorphic VTach is irregular", "Treated identically"], correctIndex: 1, answer: "Torsades de Pointes: polymorphic VTach with QRS complexes rotating around baseline, ALWAYS associated with prolonged QT. Treatment: IV magnesium (NOT amiodarone which prolongs QT). May need overdrive pacing.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-vtach-6", type: "question", question: "Most common causes of VTach?", options: ["Dehydration", "CAD, prior MI (scar reentry), cardiomyopathy, electrolyte imbalances", "URI", "UTI"], correctIndex: 1, answer: "Common VTach causes: coronary artery disease, prior MI (scar tissue reentry circuits), dilated/hypertrophic cardiomyopathy, electrolyte imbalances (hypokalemia, hypomagnesemia), drug toxicity (digoxin, QT-prolonging drugs).", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-vtach-7", type: "question", question: "First assessment for wide-complex tachycardia on the monitor?", options: ["12-lead ECG", "Check pulse and hemodynamic status", "Administer oxygen", "Call rapid response"], correctIndex: 1, answer: "Check pulse first. Pulseless VTach → defibrillation + CPR. VTach with pulse + unstable → synchronized cardioversion. Stable VTach → pharmacologic therapy. Pulse determines entire treatment pathway.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-vtach-8", type: "question", question: "Why synchronized cardioversion (not defibrillation) for VTach with a pulse?", options: ["Uses less energy", "Synchronized mode delivers shock on R wave, avoiding vulnerable T-wave period which could trigger VFib", "Less painful", "No difference"], correctIndex: 1, answer: "Synchronized cardioversion times shock to R wave, avoiding the T-wave vulnerable period (relative refractory period). Shocking on T wave could trigger VFib. Unsynchronized (defibrillation) only for pulseless rhythms.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-vtach-9", type: "question", question: "A client on amiodarone develops VTach with QTc 620 ms. What should the nurse suspect?", options: ["Amiodarone is working correctly", "Amiodarone-induced Torsades de Pointes — stop amiodarone, give IV magnesium", "Normal QTc on amiodarone", "Need higher amiodarone dose"], correctIndex: 1, answer: "Amiodarone prolongs QT. A QTc >500 ms with polymorphic VTach = drug-induced Torsades. Stop amiodarone immediately, give IV magnesium 1-2 g, avoid all QT-prolonging drugs. May need isoproterenol or overdrive pacing.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-vtach-10", type: "question", question: "What electrolyte abnormality is most commonly associated with VTach?", options: ["Hypernatremia", "Hypokalemia", "Hypercalcemia", "Hypermagnesemia"], correctIndex: 1, answer: "Hypokalemia is the most common electrolyte cause of VTach. Low K+ increases myocardial automaticity and prolongs repolarization. Always check and correct K+ (maintain >4.0 mEq/L) and Mg2+ in cardiac patients.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-vtach-11", type: "question", question: "What is an ICD and when is it indicated?", options: ["A temporary pacing device", "An implantable cardioverter-defibrillator that detects and terminates VTach/VFib; indicated for secondary prevention after cardiac arrest or high-risk primary prevention", "A type of pacemaker only", "External defibrillator"], correctIndex: 1, answer: "ICD detects VTach/VFib and delivers automatic internal shock or anti-tachycardia pacing. Indicated: survivors of cardiac arrest (secondary), EF ≤35% with heart failure (primary prevention), hypertrophic cardiomyopathy with risk factors.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-vtach-12", type: "question", question: "What medication alternative to amiodarone can be used for stable VTach?", options: ["Adenosine", "IV lidocaine or IV procainamide", "Diltiazem", "Atropine"], correctIndex: 1, answer: "IV lidocaine (class IB) is an alternative for VTach, especially in acute MI. IV procainamide (class IA) is effective but causes hypotension and requires slow infusion with BP monitoring. Both are second-line after amiodarone.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-vtach-13", type: "question", question: "When in doubt about a wide-complex tachycardia (VTach vs SVT with aberrancy), how should the nurse treat it?", options: ["Assume SVT", "Treat as VTach — safer to treat SVT as VTach than VTach as SVT", "Wait for 12-lead", "Give diltiazem"], correctIndex: 1, answer: "Cardinal rule: when uncertain, treat as VTach. VTach protocols (amiodarone, cardioversion) are safe for SVT. SVT medications (CCBs) given to VTach can cause cardiovascular collapse and death.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-vtach-14", type: "question", question: "What is AV dissociation on ECG and what does it suggest?", options: ["Normal finding", "P waves and QRS complexes at different rates with no relationship — strongly suggests VTach over SVT", "Only seen in heart block", "Indicates atrial flutter"], correctIndex: 1, answer: "AV dissociation (independent P wave and QRS rates) is a hallmark of VTach. In SVT with aberrancy, 1:1 P-QRS relationship is maintained. Finding AV dissociation on a wide-complex tachycardia strongly favors VTach diagnosis.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-vtach-15", type: "question", question: "What medications prolong QT and increase Torsades risk?", options: ["Metoprolol and lisinopril", "Amiodarone, sotalol, haloperidol, azithromycin, ondansetron", "Aspirin and acetaminophen", "Insulin and metformin"], correctIndex: 1, answer: "QT-prolonging drugs: antiarrhythmics (amiodarone, sotalol, procainamide), antipsychotics (haloperidol, quetiapine), antibiotics (azithromycin, fluoroquinolones), antiemetics (ondansetron), methadone. Monitor QTc especially in combination.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-vtach-16", type: "question", question: "A post-MI client has frequent PVCs (>10/min) and a 3-beat VTach run. What does the nurse anticipate?", options: ["No intervention needed", "Cardiac monitoring, electrolyte correction, possible amiodarone, and evaluation for ICD placement", "Immediate pacemaker", "Discharge"], correctIndex: 1, answer: "Frequent PVCs and NSVT post-MI indicate irritable myocardium and increased risk for sustained VTach/VFib. Correct K+/Mg2+, continuous telemetry, consider amiodarone, and evaluate EF for potential ICD (if EF ≤35% after optimization).", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-vtach-17", type: "question", question: "What is anti-tachycardia pacing (ATP) from an ICD?", options: ["External pacing", "The ICD delivers a rapid burst of pacing impulses faster than VTach to interrupt the reentry circuit without a shock", "Slow pacing for bradycardia", "Cardiac resynchronization"], correctIndex: 1, answer: "ATP is a painless ICD therapy where a burst of pacing impulses slightly faster than VTach rate captures the myocardium and terminates the reentry circuit. It is tried first before a shock for hemodynamically tolerated VTach to avoid painful defibrillation.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-vtach-18", type: "question", question: "What is ventricular storm?", options: ["A single PVC", "Three or more episodes of sustained VTach or VFib within 24 hours — a life-threatening emergency requiring ICU admission", "Occasional VTach", "Normal heart rhythm variant"], correctIndex: 1, answer: "Ventricular (electrical) storm: ≥3 sustained VTach/VFib episodes in 24 hours or ICD delivering ≥3 appropriate shocks. It is a cardiac emergency requiring IV amiodarone/lidocaine, sedation, beta-blocker optimization, electrolyte correction, and potentially ablation.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-vtach-19", type: "question", question: "How should the nurse care for a client whose ICD just fired (delivered a shock)?", options: ["Ignore it", "Assess level of consciousness and hemodynamics, obtain rhythm strip, report to provider, document the event and time", "Remove the ICD", "Administer atropine"], correctIndex: 1, answer: "After ICD shock: assess consciousness and hemodynamics, obtain 12-lead ECG and rhythm strip, assess for symptoms (chest pain, dizziness), notify provider, document event details. The device interrogation will show what rhythm triggered the shock.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-vtach-20", type: "question", question: "A client with VTach has a magnesium level of 1.0 mEq/L. What is the priority?", options: ["Ignore Mg level", "Replace magnesium IV — hypomagnesemia increases VTach risk and must be corrected (target >2.0 mEq/L)", "Restrict magnesium intake", "Increase calcium"], correctIndex: 1, answer: "Hypomagnesemia (normal 1.5-2.5 mEq/L) predisposes to VTach and Torsades de Pointes. IV magnesium sulfate 1-2 g over 15-60 min, then maintenance. Critical to correct in any ventricular arrhythmia along with potassium.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-vtach-21", type: "question", question: "What is polymorphic VTach WITHOUT a prolonged QT?", options: ["Torsades de Pointes", "Polymorphic VTach not related to QT prolongation — often due to myocardial ischemia; treat with amiodarone (not magnesium)", "Normal heart rhythm", "Atrial flutter"], correctIndex: 1, answer: "Polymorphic VTach with normal QT is NOT Torsades and should be treated differently: IV amiodarone IS appropriate. The most common cause is acute myocardial ischemia requiring urgent revascularization. Magnesium is not first-line for this form.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-vtach-22", type: "question", question: "What is capture beat and fusion beat on ECG during VTach?", options: ["Artifact", "Capture beat: normal-looking QRS during VTach (sinus impulse captures ventricle); Fusion beat: hybrid QRS from simultaneous ventricular and supraventricular activation. Both confirm VTach diagnosis.", "Signs of SVT", "Equipment malfunction"], correctIndex: 1, answer: "Capture beat: a normal narrow QRS complex during VTach when a sinus impulse occasionally captures the ventricle. Fusion beat: a QRS intermediate between the VTach morphology and normal sinus beat. Both prove AV dissociation and confirm VTach.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-vtach-23", type: "question", question: "A client with an ICD is receiving multiple inappropriate shocks. What should the nurse do?", options: ["Tell the patient to tolerate it", "Place a magnet over the ICD to temporarily disable shock therapy, notify the provider for urgent device interrogation", "Remove the ICD", "Give adenosine"], correctIndex: 1, answer: "A magnet placed over an ICD temporarily disables tachyarrhythmia therapy (shocks/ATP) without affecting pacing. This is appropriate for inappropriate shocks (e.g., from AFib, lead fracture, noise). Arrange urgent device interrogation.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-vtach-24", type: "question", question: "What is idiopathic VTach?", options: ["VTach only in elderly patients", "VTach occurring in structurally normal hearts, often in younger patients, with specific ECG morphologies (RVOT or fascicular VTach) and generally better prognosis", "VTach from drug overdose", "VTach in neonates only"], correctIndex: 1, answer: "Idiopathic VTach occurs in structurally normal hearts. RVOT VTach (LBBB morphology, inferior axis) and fascicular VTach (RBBB morphology, responds to verapamil) are the most common types. Generally has better prognosis and is amenable to catheter ablation.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-vtach-25", type: "question", question: "What is the recommended initial energy for synchronized cardioversion of stable VTach with a pulse?", options: ["50 J", "100 J biphasic initially", "360 J", "10 J"], correctIndex: 1, answer: "For synchronized cardioversion of monomorphic VTach with a pulse: start at 100 J biphasic. Escalate with subsequent attempts. Always confirm synchronized mode. If patient loses pulse, switch to unsynchronized defibrillation.", category: "Arrhythmias & ECG", difficulty: 2 },

  // VENTRICULAR FIBRILLATION — 25 cards
  { id: "rn-arr-vfib-1", type: "question", question: "What does VFib look like on ECG?", options: ["Regular wide QRS", "Chaotic, irregular waveform with no identifiable P, QRS, or T waves", "Normal sinus with PVCs", "Sawtooth waves"], correctIndex: 1, answer: "VFib: chaotic, disorganized pattern with no discernible P, QRS, or T waves. Zero organized cardiac output. Classified as coarse (higher amplitude, better defibrillation response) or fine (may mimic asystole).", category: "Arrhythmias & ECG", difficulty: 1 },
  { id: "rn-arr-vfib-2", type: "question", question: "Single most important intervention for VFib?", options: ["IV amiodarone", "Immediate defibrillation", "Intubation", "IV epinephrine"], correctIndex: 1, answer: "Immediate defibrillation is definitive for VFib. For every minute delayed, survival decreases 7-10%. CPR while preparing defibrillator. Initial: 120-200J biphasic.", category: "Arrhythmias & ECG", difficulty: 1 },
  { id: "rn-arr-vfib-3", type: "question", question: "When is epinephrine first given in VFib ACLS algorithm?", options: ["Before first shock", "After the second shock during CPR", "Only if amiodarone fails", "After ROSC"], correctIndex: 1, answer: "ACLS: epinephrine 1 mg IV/IO after the second shock (during CPR). Repeat q3-5min. Amiodarone 300 mg after third shock. Sequence: CPR → Shock 1 → CPR → Shock 2 → Epi + CPR → Shock 3 → Amiodarone + CPR.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-vfib-4", type: "question", question: "What are the H's and T's of reversible cardiac arrest causes?", options: ["History and Treatment", "Hypovolemia, Hypoxia, H+ (acidosis), Hypo/Hyperkalemia, Hypothermia; Tension pneumothorax, Tamponade, Toxins, Thrombosis (PE/coronary)", "Head injury and Trauma", "Heart rate and Temperature"], correctIndex: 1, answer: "H's: Hypovolemia, Hypoxia, H+ (acidosis), Hypo/Hyperkalemia, Hypothermia. T's: Tension pneumothorax, Tamponade, Toxins, Thrombosis (PE/coronary). Identifying reversible causes is essential for ROSC.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-vfib-5", type: "question", question: "After ROSC from VFib, what is critical post-arrest care?", options: ["Immediate discharge", "Targeted temperature management (TTM) at 32-36°C for ≥24 hours", "Prophylactic antibiotics", "Liberal fluid resuscitation"], correctIndex: 1, answer: "TTM at 32-36°C for ≥24 hours reduces cerebral metabolic demand and limits reperfusion injury. Monitor for: bradycardia, coagulopathy, electrolyte shifts, shivering.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-vfib-6", type: "question", question: "How to differentiate fine VFib from asystole?", options: ["Identical, treated the same", "Check multiple leads — fine VFib shows fibrillatory activity in other leads but may appear flat in one", "Fine VFib has QRS", "Asystole has P waves"], correctIndex: 1, answer: "Confirm in multiple leads (rotate 90°). Fine VFib shows low-amplitude fibrillatory activity in other leads. VFib is shockable; asystole is NOT. Also check electrode connections and gain settings.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-vfib-7", type: "question", question: "Recommended CPR rate and depth for adults?", options: ["60/min, 1 inch", "100-120/min, at least 2 inches (5 cm)", "200/min, 3 inches", "80/min, 1.5 inches"], correctIndex: 1, answer: "High-quality CPR: 100-120 compressions/min, ≥2 inches (5 cm) but ≤2.4 inches, full chest recoil, minimize interruptions (<10 sec), rotate compressors q2min.", category: "Arrhythmias & ECG", difficulty: 1 },
  { id: "rn-arr-vfib-8", type: "question", question: "What is the amiodarone dose for refractory VFib?", options: ["150 mg", "300 mg IV push first dose, then 150 mg second dose", "600 mg", "50 mg"], correctIndex: 1, answer: "Amiodarone in VFib/pulseless VTach: first dose 300 mg IV/IO push after third shock. Second dose 150 mg IV if VFib persists. Given during CPR. Lidocaine 1-1.5 mg/kg is an alternative.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-vfib-9", type: "question", question: "What is the compression-to-ventilation ratio for 2-rescuer adult CPR with advanced airway?", options: ["30:2", "Continuous compressions at 100-120/min with 1 breath every 6 seconds (10 breaths/min) — no pausing for ventilations", "15:2", "5:1"], correctIndex: 1, answer: "With an advanced airway (ETT, supraglottic), compressions are continuous (no pauses) at 100-120/min. Ventilations: 1 breath every 6 seconds (10/min). Without advanced airway: 30:2 ratio with pauses for breaths.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-vfib-10", type: "question", question: "What is the role of vasopressin in cardiac arrest?", options: ["First-line vasopressor", "Vasopressin has been removed from the ACLS algorithm; epinephrine is the only recommended vasopressor", "Used before epinephrine", "Replaces amiodarone"], correctIndex: 1, answer: "Vasopressin was removed from the 2015 ACLS guidelines. Epinephrine 1 mg IV every 3-5 minutes is the only recommended vasopressor for cardiac arrest. Vasopressin showed no survival benefit over epinephrine.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-vfib-11", type: "question", question: "During VFib arrest, why should chest compression interruptions be minimized?", options: ["Saves time", "Each interruption drops coronary perfusion pressure to zero; it takes multiple compressions to rebuild — longer pauses mean worse outcomes", "No reason to minimize", "To keep the compressor from getting tired"], correctIndex: 1, answer: "Coronary perfusion pressure (CPP) drops to zero immediately with any pause. It takes 5-10 compressions to rebuild CPP. Pre-shock and post-shock pauses should be <10 seconds. Higher CPP correlates with ROSC likelihood.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-vfib-12", type: "question", question: "A client in VFib arrest has suspected hyperkalemia (renal failure patient). What additional intervention should the nurse anticipate?", options: ["Kayexalate only", "IV calcium chloride, sodium bicarbonate, insulin/dextrose, and albuterol to emergently lower potassium", "Restrict IV fluids", "Oral potassium supplement"], correctIndex: 1, answer: "Hyperkalemia is a reversible cause (H's and T's). IV calcium (membrane stabilizer), sodium bicarbonate (drives K+ intracellularly), insulin/D50 (shifts K+), and albuterol (shifts K+) should be given during resuscitation. Dialysis may be needed post-ROSC.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-vfib-13", type: "question", question: "What is the maximum interval between last compression and shock delivery?", options: ["30 seconds", "Less than 10 seconds — minimize perishock pause", "60 seconds", "No limit"], correctIndex: 1, answer: "The perishock pause (time between last compression and shock delivery) should be <10 seconds to maintain coronary perfusion pressure. Resume compressions immediately after each shock without pausing for rhythm check until the 2-minute cycle is complete.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-vfib-14", type: "question", question: "Post-cardiac arrest, the client has ROSC but remains comatose. What neurological prognostication tool is used?", options: ["CT scan immediately", "Neurological prognostication is performed at ≥72 hours post-arrest using multimodal assessment (clinical exam, EEG, imaging, biomarkers)", "MRI within 1 hour", "Neurologic assessment at 6 hours"], correctIndex: 1, answer: "Neurological prognostication should NOT be done early. Wait ≥72 hours post-ROSC (and after rewarming from TTM). Use multimodal approach: pupillary reflexes, corneal reflexes, motor response, EEG, somatosensory evoked potentials, MRI, and NSE biomarkers.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-vfib-15", type: "question", question: "What is the recommended defibrillation energy for first shock in VFib?", options: ["50 J", "120-200 J biphasic (or 360 J monophasic)", "10 J", "400 J"], correctIndex: 1, answer: "First shock for VFib: 120-200 J biphasic (device-specific) or 360 J monophasic. Use maximum energy if unsure of device recommendations. Subsequent shocks can be at same or escalating energy levels.", category: "Arrhythmias & ECG", difficulty: 1 },
  { id: "rn-arr-vfib-16", type: "question", question: "What is the 'no-flow time' concept in cardiac arrest?", options: ["Time without IV fluids", "Total time without chest compressions during arrest — directly correlates with worse outcomes; goal is to minimize it", "Time without oxygen", "Time without ECG monitoring"], correctIndex: 1, answer: "No-flow time = total time without chest compressions during arrest. Includes: pre-CPR interval, pauses for rhythm checks, pauses for intubation, and perishock pauses. Higher no-flow time = worse neurological outcomes. Minimize all pauses.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-vfib-17", type: "question", question: "What does end-tidal CO2 (ETCO2) monitoring tell us during cardiac arrest?", options: ["Oxygen levels", "ETCO2 correlates with cardiac output from CPR quality; a sudden rise in ETCO2 may indicate ROSC", "It measures hemoglobin", "Only useful after ROSC"], correctIndex: 1, answer: "ETCO2 during arrest: correlates with CPR quality (target >10 mmHg, ideally >20 mmHg). Sudden sustained rise often indicates ROSC before a pulse is palpable. ETCO2 <10 after 20 min may suggest poor prognosis.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-vfib-18", type: "question", question: "A witnessed VFib arrest occurs in the ICU with immediate defibrillator availability. Should CPR be started before defibrillation?", options: ["Always start CPR first for 2 minutes", "For witnessed arrest with immediately available defibrillator, shock ASAP; brief CPR while charging is acceptable", "Never start CPR if defibrillator is available", "Only CPR, never defibrillate"], correctIndex: 1, answer: "For witnessed VFib with immediately available defibrillator: defibrillate as soon as possible. Perform CPR while the defibrillator charges. Early defibrillation (<3 min) has the highest survival rates for witnessed VFib.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-vfib-19", type: "question", question: "Why should IV push medications in cardiac arrest be followed by a 20 mL flush?", options: ["To hydrate the patient", "To push the medication from the peripheral IV into central circulation since there is no cardiac output", "No reason for flush", "To dilute the medication"], correctIndex: 1, answer: "During cardiac arrest, there is no cardiac output, so medications must be pushed into central circulation by CPR-generated flow. A 20 mL NS flush after each IV push medication ensures delivery from peripheral to central circulation.", category: "Arrhythmias & ECG", difficulty: 1 },
  { id: "rn-arr-vfib-20", type: "question", question: "When should resuscitation efforts be terminated in VFib arrest?", options: ["After 10 minutes always", "No fixed time — consider ETCO2, duration, reversible causes, and clinical factors; refractory VFib may warrant ECMO if available", "After 2 shocks", "After epinephrine fails"], correctIndex: 1, answer: "No fixed termination time. Consider: arrest duration, ETCO2 trends, all H's and T's addressed, quality of CPR, and patient factors. Refractory VFib may warrant extracorporeal CPR (ECMO) in select centers. Decision is team-based.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-vfib-21", type: "question", question: "What is the danger of 'stacking shocks' (multiple rapid shocks without CPR between them)?", options: ["More effective", "Prolonged interruption in CPR reduces coronary perfusion pressure and worsens outcomes", "Saves time", "No danger"], correctIndex: 1, answer: "Current ACLS guidelines recommend single-shock strategy: one shock followed by immediate CPR for 2 minutes before rechecking rhythm. Stacking shocks creates prolonged pauses without compressions, dropping coronary perfusion pressure.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-vfib-22", type: "question", question: "What is the role of ECMO in cardiac arrest?", options: ["Standard treatment everywhere", "Extracorporeal CPR (ECPR) provides mechanical circulatory support for refractory cardiac arrest in select patients at specialized centers", "Only for pediatric patients", "Replaces CPR immediately"], correctIndex: 1, answer: "ECPR uses venoarterial ECMO to provide mechanical circulatory support during refractory cardiac arrest. Requires specialized team and equipment. Best outcomes: witnessed arrest, shockable rhythm, short no-flow time, younger patients. Not available at all centers.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-vfib-23", type: "question", question: "After ROSC, a post-arrest client has ST elevation on 12-lead ECG. What should the nurse anticipate?", options: ["Repeat cardiac arrest only", "Emergent cardiac catheterization/PCI — acute MI may have caused the arrest", "No further workup needed", "Discharge planning"], correctIndex: 1, answer: "Post-ROSC STEMI requires emergent cardiac catheterization regardless of neurological status. Acute MI is a common cause of VFib arrest. Early PCI improves survival. Other post-arrest care: TTM, hemodynamic optimization, neuroprotection.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-vfib-24", type: "question", question: "What is the nurse's documentation responsibility during a code?", options: ["Only document after code ends", "A dedicated recorder documents: time of arrest, interventions with times, medications with doses/times, rhythm changes, and defibrillation attempts", "No documentation needed", "Only document medications"], correctIndex: 1, answer: "The code recorder documents in real-time: time of arrest/CPR start, all rhythm changes, each defibrillation (time and energy), all medications (drug, dose, route, time), intubation time, ROSC time or time of death. Accurate time documentation is critical.", category: "Arrhythmias & ECG", difficulty: 1 },
  { id: "rn-arr-vfib-25", type: "question", question: "What post-arrest complication is the most common cause of death?", options: ["Renal failure", "Post-cardiac arrest syndrome — includes anoxic brain injury, myocardial dysfunction, systemic ischemia-reperfusion response, and persistent precipitating cause", "Infection", "GI bleeding"], correctIndex: 1, answer: "Post-cardiac arrest syndrome includes: anoxic brain injury (leading cause of death post-ROSC), global myocardial stunning, systemic ischemia-reperfusion injury (similar to sepsis), and the original precipitating pathology. Multi-organ support is needed.", category: "Arrhythmias & ECG", difficulty: 3 },

  // HEART BLOCKS — 25 cards
  { id: "rn-arr-hblock-1", type: "question", question: "What defines first-degree AV block?", options: ["Dropped QRS complexes", "PR interval >0.20 seconds with 1:1 P-to-QRS ratio", "No P waves", "Wide QRS"], correctIndex: 1, answer: "First-degree AV block: prolonged PR (>0.20 sec) with every P wave followed by a QRS (1:1 conduction). Delayed conduction through AV node. Usually benign, no treatment needed.", category: "Arrhythmias & ECG", difficulty: 1 },
  { id: "rn-arr-hblock-2", type: "question", question: "Hallmark of Mobitz Type I (Wenckebach)?", options: ["Constant PR with random dropped QRS", "Progressive PR prolongation until a QRS is dropped, then cycle repeats", "Complete AV dissociation", "Inverted P waves"], correctIndex: 1, answer: "Wenckebach: progressively lengthening PR until P wave not conducted (dropped QRS), then reset. At AV node level. Often benign — seen in inferior MI, with beta-blockers/digoxin. Usually doesn't require pacing.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-hblock-3", type: "question", question: "Why is Mobitz Type II more dangerous than Type I?", options: ["Always faster rate", "Block is infranodal (His/bundle branches) and can suddenly progress to complete heart block without warning", "Causes hypertension", "Type II responds to atropine"], correctIndex: 1, answer: "Mobitz II: infranodal block with sudden unpredictable dropped QRS without PR prolongation. High risk of sudden complete heart block and hemodynamic collapse. Pacemaker usually indicated.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-hblock-4", type: "question", question: "In third-degree heart block, what is the P wave-QRS relationship?", options: ["1:1 with prolonged PR", "No relationship — atria and ventricles beat independently (AV dissociation)", "P waves absent", "Every other P conducted"], correctIndex: 1, answer: "Complete AV dissociation: no atrial impulses conducted. P waves march at their own rate (60-100). QRS at slower escape rate (junctional 40-60 or ventricular 20-40). PR intervals vary randomly.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-hblock-5", type: "question", question: "Why does atropine often fail in third-degree heart block?", options: ["Not anticholinergic", "Atropine enhances AV nodal conduction but complete block is often infranodal where atropine has no effect", "Always effective", "Slows heart rate"], correctIndex: 1, answer: "Atropine blocks parasympathetic input to AV node. Infranodal complete block doesn't respond because tissue below AV node lacks parasympathetic innervation. Pacing is required.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-hblock-6", type: "question", question: "Bridge therapy for symptomatic complete heart block awaiting pacemaker?", options: ["IV amiodarone", "Transcutaneous pacing", "Digoxin", "IV diltiazem"], correctIndex: 1, answer: "Transcutaneous pacing: apply pads anteriorly/posteriorly, set rate 60-80, increase mA until electrical capture (spike followed by wide QRS). Provide analgesia — external pacing is painful.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-hblock-7", type: "question", question: "How to differentiate Mobitz I from Mobitz II on rhythm strip?", options: ["Type I has wider QRS", "Type I: progressive PR prolongation before dropped beat. Type II: constant PR with sudden dropped beat, often with wide QRS", "Cannot differentiate", "Type II has irregular atrial rhythm"], correctIndex: 1, answer: "Type I: PR gradually lengthens before drop (grouped beating). Type II: constant PR, sudden drop without warning. Type II often has wide QRS (bundle branch block) because block is at lower conduction level.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-hblock-8", type: "question", question: "Inferior MI develops new second-degree AV block. Which type and why?", options: ["Type II — inferior MI affects bundles", "Type I (Wenckebach) — the RCA supplies the AV node in 85-90% of people", "Third-degree always", "First-degree only"], correctIndex: 1, answer: "Inferior MI often produces Wenckebach because RCA supplies AV node in 85-90%. AV nodal ischemia causes reversible conduction delay, typically resolves in days. Anterior MI tends to cause Type II or complete block.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-hblock-9", type: "question", question: "What is the normal PR interval range?", options: ["0.06-0.10 sec", "0.12-0.20 seconds", "0.20-0.40 sec", "0.40-0.60 sec"], correctIndex: 1, answer: "Normal PR interval: 0.12-0.20 seconds (3-5 small boxes on ECG paper). >0.20 sec = first-degree AV block. <0.12 sec with delta wave = WPW pre-excitation.", category: "Arrhythmias & ECG", difficulty: 1 },
  { id: "rn-arr-hblock-10", type: "question", question: "What escape rhythm maintains cardiac output in complete heart block?", options: ["No escape rhythm exists", "Junctional escape (40-60 bpm, narrow QRS) if block is at AV node; ventricular escape (20-40 bpm, wide QRS) if infranodal", "Sinus rhythm continues normally", "Atrial escape only"], correctIndex: 1, answer: "Below the block, subsidiary pacemakers generate escape rhythms. Junctional escape: 40-60 bpm with narrow QRS. Ventricular escape: 20-40 bpm with wide QRS, less reliable. The lower the escape, the more dangerous.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-hblock-11", type: "question", question: "When is a permanent pacemaker indicated for heart blocks?", options: ["All first-degree blocks", "Symptomatic second-degree Type II, high-grade AV block, and symptomatic complete heart block", "Only for temporary blocks", "Never indicated"], correctIndex: 1, answer: "Permanent pacemaker indications: symptomatic Mobitz Type II, high-grade (2:1 or 3:1) AV block, third-degree (complete) heart block (especially with symptoms, wide escape, or ventricular rate <40). First-degree and asymptomatic Wenckebach rarely need pacing.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-hblock-12", type: "question", question: "What is the significance of a wide QRS complex in heart block?", options: ["Normal variant", "Indicates the block is at or below the bundle branches (infranodal) — more dangerous with higher risk of progression to complete block", "Indicates atrial origin", "Better prognosis than narrow QRS block"], correctIndex: 1, answer: "Wide QRS (>0.12 sec, bundle branch block morphology) in second or third-degree heart block localizes the block below the AV node. Infranodal blocks are more dangerous (less reliable escape rhythm, higher risk of asystole) and almost always need permanent pacing.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-hblock-13", type: "question", question: "What medications can cause or worsen AV block?", options: ["Aspirin and acetaminophen", "Beta-blockers, calcium channel blockers (non-DHP), digoxin, amiodarone, and adenosine", "ACE inhibitors only", "Statins only"], correctIndex: 1, answer: "Drugs that slow AV conduction: beta-blockers, non-DHP CCBs (diltiazem, verapamil), digoxin, amiodarone, adenosine, and clonidine. These are common reversible causes of AV block. Review medication list before starting pacing.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-hblock-14", type: "question", question: "A pacemaker patient's ECG shows pacing spikes before each QRS and each P wave. What type of pacemaker is this?", options: ["Single-chamber ventricular pacer", "Dual-chamber pacemaker (DDD) — pacing both atrium and ventricle", "No pacemaker present", "Defibrillator only"], correctIndex: 1, answer: "Pacing spikes before P waves AND QRS complexes indicate a dual-chamber (DDD) pacemaker pacing both atrium and ventricle. This maintains AV synchrony, which is important for optimal hemodynamics (preserves atrial kick).", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-hblock-15", type: "question", question: "What does 'failure to sense' mean in a pacemaker patient?", options: ["Pacemaker doesn't deliver impulses", "Pacemaker fails to detect the heart's intrinsic rhythm, delivering pacing spikes at inappropriate times including near native beats", "Battery depletion", "Lead fracture always"], correctIndex: 1, answer: "Undersensing: pacemaker fails to detect native cardiac activity, resulting in inappropriate pacing spikes that may compete with intrinsic rhythm. Can cause R-on-T phenomenon triggering VTach/VFib. Increase sensitivity (lower mV threshold).", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-hblock-16", type: "question", question: "What education does the nurse provide to a client with a new permanent pacemaker?", options: ["No restrictions at all", "Avoid MRI (unless MRI-conditional), keep cell phone on opposite side, carry ID card, avoid large magnets, report signs of infection at site", "Avoid all physical activity forever", "No follow-up needed"], correctIndex: 1, answer: "Pacemaker education: carry ID card always, avoid strong magnetic fields (MRI check device compatibility, welding equipment), keep cell phone 6 inches from device, report: signs of infection (redness, swelling, drainage, fever), hiccups (lead displacement), dizziness. Regular device checks.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-hblock-17", type: "question", question: "What is high-grade AV block?", options: ["Same as first-degree block", "Two or more consecutive P waves not conducted (e.g., 3:1 or 4:1 block with very slow ventricular rate) — indicates severe conduction disease", "Complete heart block", "Wenckebach"], correctIndex: 1, answer: "High-grade AV block: ≥2 consecutive non-conducted P waves (e.g., 3:1, 4:1 block). More severe than standard second-degree blocks. Often symptomatic due to slow ventricular rate. Usually requires permanent pacing.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-hblock-18", type: "question", question: "What assessment is critical after temporary pacemaker insertion via femoral or subclavian approach?", options: ["Only check pacemaker settings", "Monitor insertion site for bleeding/hematoma, assess distal pulses, check for pneumothorax (subclavian), verify capture on monitor", "No assessment needed", "Only check blood glucose"], correctIndex: 1, answer: "Post-insertion: monitor for site bleeding/hematoma, check neurovascular status of affected limb (femoral), chest X-ray to confirm lead position and rule out pneumothorax (subclavian), verify electrical capture on monitor, immobilize extremity.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-hblock-19", type: "question", question: "A client with a pacemaker set at 70 bpm has a heart rate of 54 bpm. What does this indicate?", options: ["Normal pacemaker function", "Pacemaker malfunction — either failure to capture, failure to output, or lead displacement. Immediate assessment needed", "Expected finding", "Need to check only at next appointment"], correctIndex: 1, answer: "A rate below the set pacemaker rate indicates malfunction. Possible causes: failure to capture (spikes without QRS), failure to output (no spikes), lead displacement, battery depletion, or electromagnetic interference. Assess immediately, check connections, CXR for lead position.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-hblock-20", type: "question", question: "What is the Stokes-Adams attack?", options: ["A type of stroke", "Sudden syncope or near-syncope from transient complete heart block or asystole, often followed by flushing upon recovery", "Seizure disorder", "Panic attack"], correctIndex: 1, answer: "Stokes-Adams attack: sudden syncope from transient complete heart block causing cerebral hypoperfusion. The patient may have seizure-like activity from cerebral anoxia. Characteristic facial flushing occurs upon recovery due to reactive hyperemia. Requires pacemaker.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-hblock-21", type: "question", question: "Why is external (transcutaneous) pacing painful?", options: ["It causes burns", "Large electrical currents pass through chest wall skin and skeletal muscle causing involuntary contractions and discomfort", "It is not painful", "Only children feel pain from it"], correctIndex: 1, answer: "Transcutaneous pacing sends electrical current through chest wall, stimulating skeletal muscle contraction (causing visible chest wall twitching) and activating pain receptors. Adequate sedation/analgesia (fentanyl, midazolam) is essential. It is a temporary bridge.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-hblock-22", type: "question", question: "What is the significance of a new bifascicular block (RBBB + left anterior fascicular block) in acute MI?", options: ["Benign finding", "Indicates extensive conduction system damage with risk of progression to complete heart block — may need prophylactic pacing", "Only affects elderly", "Improves prognosis"], correctIndex: 1, answer: "New bifascicular block in acute MI (especially anterior) indicates widespread damage to the His-Purkinje system. Risk of sudden complete heart block is significant. Prophylactic transcutaneous pacing pads should be placed, and transvenous pacing may be indicated.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-hblock-23", type: "question", question: "What is the atropine dose for symptomatic bradycardia from heart block?", options: ["0.1 mg IV", "0.5 mg IV, may repeat q3-5 min, maximum 3 mg total", "5 mg IV", "10 mg IM"], correctIndex: 1, answer: "Atropine for bradycardia: 0.5 mg IV q3-5 min, max total 3 mg. Doses <0.5 mg can cause paradoxical bradycardia (central vagal stimulation). Atropine may be ineffective for infranodal blocks and should not delay pacing.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-hblock-24", type: "question", question: "A client with Lyme disease develops new second-degree AV block. What is the likely cause and treatment?", options: ["Unrelated to Lyme", "Lyme carditis — AV nodal inflammation; usually resolves with antibiotic treatment (IV ceftriaxone) and may need temporary pacing", "Needs permanent pacemaker immediately", "Caused by tick allergic reaction"], correctIndex: 1, answer: "Lyme carditis can cause AV blocks (usually at AV nodal level, Wenckebach most common but can progress to complete block). It is typically reversible with IV antibiotics (ceftriaxone). Temporary pacing may be needed. Most patients do not require permanent pacemaker.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-hblock-25", type: "question", question: "What is 2:1 AV block and why is it difficult to classify?", options: ["Always Mobitz Type II", "Every other P wave is conducted; cannot distinguish Type I from Type II because there are not enough consecutive conducted beats to assess PR trend", "Always Mobitz Type I", "Same as complete heart block"], correctIndex: 1, answer: "In 2:1 AV block, every other P wave is blocked. Since there is only one PR interval between dropped beats, you cannot determine if PR would have prolonged (Type I) or stayed constant (Type II). QRS width, clinical context, and atropine response help differentiate.", category: "Arrhythmias & ECG", difficulty: 3 },

  // SINUS BRADYCARDIA & TACHYCARDIA — 25 cards
  { id: "rn-arr-sinus-1", type: "question", question: "First-line medication for symptomatic sinus bradycardia per ACLS?", options: ["Epinephrine", "Atropine 0.5 mg IV", "Amiodarone", "Adenosine"], correctIndex: 1, answer: "Atropine 0.5 mg IV: blocks vagal tone on SA node, increasing HR. May repeat q3-5min, max 3 mg. Doses <0.5 mg may cause paradoxical bradycardia.", category: "Arrhythmias & ECG", difficulty: 1 },
  { id: "rn-arr-sinus-2", type: "question", question: "Which symptoms indicate sinus bradycardia requires treatment?", options: ["No symptoms — all bradycardia needs treatment", "Hypotension, syncope, altered mental status, chest pain, or shock", "Fatigue only", "Elevated BP"], correctIndex: 1, answer: "Treat only if symptomatic: hypotension (SBP <90), syncope/presyncope, AMS, chest pain, shock, or acute HF. Asymptomatic bradycardia (athletes, sleep) does not require intervention.", category: "Arrhythmias & ECG", difficulty: 1 },
  { id: "rn-arr-sinus-3", type: "question", question: "Sinus bradycardia (HR 42) unresponsive to atropine. Next intervention?", options: ["More atropine beyond max", "Transcutaneous pacing or dopamine/epinephrine infusion", "Synchronized cardioversion", "IV adenosine"], correctIndex: 1, answer: "If atropine fails: transcutaneous pacing (most reliable), dopamine 5-20 mcg/kg/min, or epinephrine 2-10 mcg/min. Prepare for transvenous pacing if needed.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-sinus-4", type: "question", question: "Cushing's triad (bradycardia, hypertension, irregular respirations) indicates what?", options: ["Cardiac tamponade", "Critically elevated ICP with brainstem herniation", "Cardiogenic shock", "Neurogenic shock"], correctIndex: 1, answer: "Cushing's triad: late sign of dangerously elevated ICP indicating brainstem herniation. Bradycardia from vagal stimulation as brainstem is compressed. Neurosurgical emergency — treat ICP, not the bradycardia.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-sinus-5", type: "question", question: "What is sick sinus syndrome?", options: ["Heart failure", "SA node dysfunction causing alternating bradycardia and tachycardia (tachy-brady syndrome)", "Sinus infection", "Congenital septal defect"], correctIndex: 1, answer: "Sick sinus syndrome: SA node dysfunction with inappropriate bradycardia, sinus arrest, sinoatrial exit block, and tachy-brady syndrome. Affects older adults. Often requires permanent pacemaker.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-sinus-6", type: "question", question: "Specific antidote for beta-blocker toxicity causing bradycardia?", options: ["Naloxone", "Glucagon", "Flumazenil", "Protamine"], correctIndex: 1, answer: "Glucagon: stimulates cardiac contractility and HR through non-adrenergic mechanism (increases cAMP independently of beta receptors). Dose: 3-10 mg IV bolus then infusion. Atropine may be tried but often ineffective in severe OD.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-sinus-7", type: "question", question: "When assessing sinus tachycardia, what should the nurse always consider?", options: ["Always pathologic, needs medication", "Sinus tachycardia is compensatory — always treat the underlying cause, not the tachycardia", "Only during exercise", "Always defibrillate"], correctIndex: 1, answer: "Sinus tachycardia is nearly always a compensatory response: pain, fever, anxiety, hypovolemia, anemia, hypoxia, HF, PE, infection, medications. Treat the cause. Lowering HR without addressing cause can be dangerous.", category: "Arrhythmias & ECG", difficulty: 1 },
  { id: "rn-arr-sinus-8", type: "question", question: "Postop patient: sinus tachycardia (HR 128), RR 28, BP 88/56, decreased UOP. What to suspect?", options: ["Normal postop response", "Hypovolemia from hemorrhage", "Medication side effect", "Anxiety"], correctIndex: 1, answer: "Sinus tachycardia + tachypnea + hypotension + oliguria in postop patient strongly suggests hypovolemia from hemorrhage. Check drains, assess for overt/occult bleeding, anticipate fluid resuscitation.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-sinus-9", type: "question", question: "What antidote is used for calcium channel blocker overdose causing bradycardia?", options: ["Glucagon only", "IV calcium gluconate or calcium chloride", "Vitamin K", "Protamine"], correctIndex: 1, answer: "IV calcium (calcium gluconate 3 g or calcium chloride 1 g) directly antagonizes CCB effects on cardiac conduction and contractility. Also consider high-dose insulin-euglycemia therapy and vasopressors for severe toxicity.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-sinus-10", type: "question", question: "A healthy 25-year-old athlete has a resting HR of 48 bpm. Is this pathologic?", options: ["Always pathologic", "No — physiologic sinus bradycardia is common in well-conditioned athletes due to increased vagal tone and stroke volume", "Needs immediate pacing", "Indicates sick sinus syndrome"], correctIndex: 1, answer: "Athletic bradycardia is physiologic. Enhanced parasympathetic tone and increased stroke volume reduce resting HR. Asymptomatic bradycardia in athletes is normal and does not require treatment unless symptomatic.", category: "Arrhythmias & ECG", difficulty: 1 },
  { id: "rn-arr-sinus-11", type: "question", question: "A client on digoxin and metoprolol has HR 44. Which medication is most likely contributing?", options: ["Neither", "Both — digoxin slows AV conduction and metoprolol slows SA node; combined effect causes excessive bradycardia", "Only aspirin", "Only lisinopril"], correctIndex: 1, answer: "Digoxin (slows AV conduction, increases vagal tone) + beta-blocker (slows SA and AV node) = additive bradycardic effect. Both should be held, monitor K+ (hypokalemia enhances digoxin toxicity), and check digoxin level.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-sinus-12", type: "question", question: "When is isoproterenol used for bradycardia?", options: ["First-line for all bradycardia", "Rarely used; considered for symptomatic bradycardia refractory to atropine when pacing is not available, and specifically for Torsades with bradycardia", "Never used", "Only in children"], correctIndex: 1, answer: "Isoproterenol (pure beta-agonist) increases HR and contractility. Rarely used for bradycardia (atropine and pacing preferred). Main indication: Torsades with bradycardia (increases HR to shorten QT) when overdrive pacing is unavailable.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-sinus-13", type: "question", question: "What does the nurse assess in a client with sinus tachycardia and fever?", options: ["Only the fever", "Assess for source of infection (cultures, WBC, lactate) — sinus tachycardia with fever may indicate sepsis which can rapidly deteriorate", "Heart rhythm only", "Lung sounds only"], correctIndex: 1, answer: "Sinus tachycardia with fever: assess for sepsis (blood cultures, lactate, WBC, urinalysis). Apply SIRS/sepsis criteria. Early recognition and treatment (antibiotics, fluids) improve outcomes. Monitor for hemodynamic deterioration.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-sinus-14", type: "question", question: "What is the danger of aggressively treating sinus tachycardia with beta-blockers in a hypovolemic patient?", options: ["No danger", "Beta-blockers remove the compensatory tachycardia, causing cardiovascular collapse — the HR is maintaining cardiac output", "Improves outcome", "Only causes mild fatigue"], correctIndex: 1, answer: "In hypovolemia, tachycardia is a compensatory mechanism maintaining cardiac output. Beta-blocking the tachycardia removes this compensation, causing precipitous BP drop and cardiovascular collapse. Treat the volume deficit, not the heart rate.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-sinus-15", type: "question", question: "A client receiving IV dobutamine develops sinus tachycardia HR 130. Is this expected?", options: ["No, never happens", "Yes — dobutamine is a beta-1 agonist that increases heart rate as a known side effect; dose reduction may be needed if HR is excessive", "Indicates allergic reaction", "Indicates drug error"], correctIndex: 1, answer: "Dobutamine (beta-1 agonist) increases contractility but also increases HR (positive chronotropy). Sinus tachycardia is a known dose-related side effect. May need dose reduction if HR becomes excessive or causes myocardial ischemia.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-sinus-16", type: "question", question: "What is inappropriate sinus tachycardia (IST)?", options: ["Normal response to exercise", "Persistently elevated resting HR >100 bpm with exaggerated rate response to minimal exertion, without identifiable cause", "Sinus tachycardia from hemorrhage", "AFib misidentified as sinus tach"], correctIndex: 1, answer: "IST: resting HR >100 bpm (or disproportionate to activity level) without an identifiable cause. Diagnosis of exclusion. Treatment: ivabradine (If channel blocker), beta-blockers, or catheter ablation of the sinus node in refractory cases.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-sinus-17", type: "question", question: "What effect does hypothyroidism have on heart rate?", options: ["Tachycardia", "Sinus bradycardia — decreased thyroid hormone reduces metabolic rate and cardiac chronotropy", "No effect", "Causes AFib"], correctIndex: 1, answer: "Hypothyroidism causes sinus bradycardia due to decreased metabolic demand and reduced cardiac sensitivity to catecholamines. Check TSH in unexplained bradycardia. Thyroid replacement gradually normalizes HR.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-sinus-18", type: "question", question: "A client in the ICU develops sinus tachycardia after suctioning. Why?", options: ["Equipment malfunction", "Suctioning stimulates the sympathetic nervous system and can cause hypoxia — both trigger tachycardia", "Allergic reaction to suction catheter", "Medication timing coincidence"], correctIndex: 1, answer: "Tracheal suctioning can cause: vagal stimulation (initially bradycardia), then sympathetic response (tachycardia), hypoxia (triggers compensatory tachycardia), coughing, and bronchospasm. Pre-oxygenate before suctioning. Limit suction to 10-15 seconds.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-sinus-19", type: "question", question: "What is the dopamine dose range for treating symptomatic bradycardia?", options: ["1-2 mcg/kg/min", "5-20 mcg/kg/min (chronotropic dose range)", "0.1 mcg/kg/min", "100 mcg/kg/min"], correctIndex: 1, answer: "Dopamine 5-20 mcg/kg/min provides chronotropic (heart rate) and inotropic (contractility) support for symptomatic bradycardia refractory to atropine. At these doses, beta-1 stimulation predominates. Higher doses add alpha vasoconstriction.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-sinus-20", type: "question", question: "A client has sinus tachycardia HR 118, and labs show hemoglobin 6.2 g/dL. What is the cause?", options: ["Anxiety", "Compensatory tachycardia from severe anemia — the heart pumps faster to maintain oxygen delivery with reduced oxygen-carrying capacity", "Medication reaction", "Hyperthyroidism"], correctIndex: 1, answer: "Severe anemia (Hgb 6.2) reduces oxygen-carrying capacity. The heart compensates by increasing rate to maintain oxygen delivery. Treatment: transfuse pRBCs as ordered, identify and treat the cause of anemia. Don't treat the tachycardia — treat the anemia.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-sinus-21", type: "question", question: "What is reflex (neurogenic) bradycardia?", options: ["Bradycardia from exercise", "Bradycardia caused by vagal nerve stimulation from events such as vomiting, bearing down, carotid massage, or increased ICP", "Medication-induced bradycardia", "Bradycardia in athletes"], correctIndex: 1, answer: "Reflex bradycardia: vagus nerve activation from various stimuli — vomiting, straining (Valsalva), ocular pressure, carotid massage, increased ICP (Cushing reflex). Usually transient. Persistent or symptomatic cases may need atropine.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-sinus-22", type: "question", question: "How does the nurse determine if sinus tachycardia is 'appropriate' vs concerning?", options: ["All tachycardia is the same", "Appropriate sinus tachycardia has an identifiable cause proportional to the rate; absence of an identifiable cause or disproportionate rate warrants investigation", "Check only blood pressure", "Order CXR only"], correctIndex: 1, answer: "Assess for identifiable causes: fever, pain, anxiety, activity, hypovolemia, anemia, hypoxia, PE, medications. If no cause is found or rate is disproportionate, investigate: PE, sepsis, thyrotoxicosis, cardiac tamponade, or IST.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-sinus-23", type: "question", question: "What is the epinephrine infusion dose for bradycardia refractory to atropine?", options: ["1 mg IV push", "2-10 mcg/min continuous infusion", "100 mcg bolus", "0.01 mcg/min"], correctIndex: 1, answer: "Epinephrine infusion 2-10 mcg/min for refractory symptomatic bradycardia (alternative to dopamine or when pacing is unavailable). The 1 mg IV push dose is for cardiac arrest only. Titrate to desired heart rate and blood pressure.", category: "Arrhythmias & ECG", difficulty: 2 },
  { id: "rn-arr-sinus-24", type: "question", question: "A spinal cord injury patient at T4 level develops sinus bradycardia HR 40 and hypotension. What is the mechanism?", options: ["Hypovolemia", "Neurogenic shock — loss of sympathetic outflow below the injury causes unopposed parasympathetic tone leading to bradycardia and vasodilation", "Cardiogenic shock", "Septic shock"], correctIndex: 1, answer: "Neurogenic shock from high spinal cord injury (above T6): loss of sympathetic nervous system causes unopposed vagal tone (bradycardia) and loss of vascular tone (vasodilation, hypotension). Warm, dry skin differentiates from hypovolemic shock. Treat with atropine, vasopressors.", category: "Arrhythmias & ECG", difficulty: 3 },
  { id: "rn-arr-sinus-25", type: "question", question: "What is chronotropic incompetence?", options: ["Normal heart rate response", "Inability of the heart rate to increase appropriately with exercise or physiologic demand — may indicate SA node dysfunction or medication effect", "Excessive heart rate response", "Only occurs in children"], correctIndex: 1, answer: "Chronotropic incompetence: failure of HR to rise adequately with exercise (typically <80% of age-predicted maximum HR). Causes: SA node disease, medications (beta-blockers), autonomic dysfunction. Symptoms: exercise intolerance, fatigue. Rate-responsive pacemaker may be indicated.", category: "Arrhythmias & ECG", difficulty: 3 },

  // CHD OVERVIEW — 25 cards
  { id: "rn-chd-overview-1", type: "question", question: "Fundamental difference between cyanotic and acyanotic CHD?", options: ["Cyanotic always more severe", "Cyanotic: deoxygenated blood enters systemic circulation (R→L shunt); Acyanotic: oxygenated blood recirculates to lungs (L→R shunt)", "Acyanotic always needs surgery", "No difference"], correctIndex: 1, answer: "Cyanotic: right-to-left shunting bypasses lungs causing cyanosis. Acyanotic: left-to-right shunting causes pulmonary overcirculation and volume overload without initial cyanosis.", category: "Pediatrics/CHD", difficulty: 2 },
  { id: "rn-chd-overview-2", type: "question", question: "What are the 5 T's of cyanotic heart defects?", options: ["VSD, ASD, PDA", "Tetralogy of Fallot, Transposition, Truncus Arteriosus, Tricuspid Atresia, TAPVR", "Coarctation, MS, AS", "PFO only"], correctIndex: 1, answer: "5 T's: Tetralogy of Fallot, Transposition of Great Arteries, Truncus Arteriosus, Tricuspid Atresia, Total Anomalous Pulmonary Venous Return. All cause mixing of deoxygenated blood into systemic circulation.", category: "Pediatrics/CHD", difficulty: 2 },
  { id: "rn-chd-overview-3", type: "question", question: "What medication keeps the ductus arteriosus open?", options: ["Indomethacin", "Prostaglandin E1 (alprostadil)", "Ibuprofen", "Digoxin"], correctIndex: 1, answer: "PGE1 (alprostadil) maintains ductal patency in ductal-dependent lesions. Monitor for apnea (10-12%), have intubation equipment at bedside, monitor temperature and BP.", category: "Pediatrics/CHD", difficulty: 2 },
  { id: "rn-chd-overview-4", type: "question", question: "What is Eisenmenger syndrome?", options: ["Congenital valve defect", "Reversal of L→R shunt to R→L due to irreversible pulmonary hypertension", "Neonatal arrhythmia", "Cardiomyopathy"], correctIndex: 1, answer: "Long-standing L→R shunt causes pulmonary vascular remodeling and irreversible pulmonary HTN. When pulmonary pressure exceeds systemic, shunt reverses (R→L) causing cyanosis. Surgical repair contraindicated at this stage.", category: "Pediatrics/CHD", difficulty: 3 },
  { id: "rn-chd-overview-5", type: "question", question: "How does fetal circulation differ from postnatal?", options: ["No difference", "Fetal has three shunts (ductus venosus, foramen ovale, ductus arteriosus) bypassing the lungs", "Fetal lungs are primary gas exchange", "Fetal heart has 2 chambers"], correctIndex: 1, answer: "Three fetal shunts bypass non-functioning lungs: ductus venosus (bypasses liver), foramen ovale (R→L atrial shunt), ductus arteriosus (PA→aorta). First breath triggers closure of these shunts.", category: "Pediatrics/CHD", difficulty: 2 },
  { id: "rn-chd-overview-6", type: "question", question: "A cyanotic newborn doesn't improve with 100% O2 (hyperoxia test). What does this suggest?", options: ["RDS", "Cyanotic congenital heart defect", "Normal transition", "Anemia"], correctIndex: 1, answer: "Failed hyperoxia test (PaO2 doesn't rise >100 mmHg with 100% FiO2) strongly suggests cyanotic CHD. Intracardiac shunting bypasses lungs, so supplemental O2 cannot improve oxygenation. Pulmonary causes typically respond to O2.", category: "Pediatrics/CHD", difficulty: 3 },
  { id: "rn-chd-overview-7", type: "question", question: "Signs of heart failure in an infant with CHD?", options: ["Polycythemia only", "Tachypnea, diaphoresis during feeding, poor weight gain, hepatomegaly, tachycardia", "Bradycardia and hypothermia", "Elevated BP only"], correctIndex: 1, answer: "Infant HF differs from adults: tachypnea (especially feeding), feeding diaphoresis, prolonged feeds, failure to thrive, hepatomegaly, tachycardia, irritability. Peripheral edema rare in infants. Weigh diapers for I&O.", category: "Pediatrics/CHD", difficulty: 2 },
  { id: "rn-chd-overview-8", type: "question", question: "What medication is used to CLOSE a PDA?", options: ["Prostaglandin E1", "Indomethacin or ibuprofen (inhibit prostaglandin synthesis)", "Alprostadil", "Digoxin"], correctIndex: 1, answer: "Indomethacin and ibuprofen are prostaglandin synthesis inhibitors that promote PDA closure. This is the OPPOSITE of PGE1 which keeps PDA open. Used in premature infants with hemodynamically significant PDA.", category: "Pediatrics/CHD", difficulty: 2 },
  { id: "rn-chd-overview-9", type: "question", question: "What does pulse oximetry screening detect in newborns?", options: ["Hearing loss", "Critical congenital heart disease — SpO2 measured in right hand and either foot", "Metabolic disorders", "Jaundice"], correctIndex: 1, answer: "Newborn CCHD screening: SpO2 in right hand (preductal) and either foot (postductal) at 24-48 hours. Failed screen: SpO2 <95% in either extremity, or >3% difference between sites. Identifies ductal-dependent and cyanotic lesions before symptoms.", category: "Pediatrics/CHD", difficulty: 2 },
  { id: "rn-chd-overview-10", type: "question", question: "What is the most common congenital heart defect overall?", options: ["TOF", "Ventricular septal defect (VSD)", "ASD", "PDA"], correctIndex: 1, answer: "VSD is the most common CHD (25-30% of all CHD). It involves an abnormal opening in the interventricular septum causing L→R shunting. Small VSDs may close spontaneously; large ones need surgical repair.", category: "Pediatrics/CHD", difficulty: 1 },
  { id: "rn-chd-overview-11", type: "question", question: "What is a ductal-dependent lesion?", options: ["A lesion that doesn't need the ductus", "A heart defect where systemic or pulmonary blood flow depends on the PDA remaining open to survive", "Only PDA itself", "Valvular disease only"], correctIndex: 1, answer: "Ductal-dependent lesions require PDA for either pulmonary blood flow (e.g., pulmonary atresia, critical PS) or systemic blood flow (e.g., HLHS, critical coarctation, interrupted aortic arch). PGE1 is lifesaving until surgical intervention.", category: "Pediatrics/CHD", difficulty: 2 },
  { id: "rn-chd-overview-12", type: "question", question: "What is the continuous machinery murmur characteristic of?", options: ["VSD", "Patent ductus arteriosus (PDA)", "ASD", "Coarctation"], correctIndex: 1, answer: "PDA produces a characteristic continuous 'machinery-like' murmur heard best at the left upper sternal border/infraclavicular area. The continuous quality occurs because flow through the PDA happens in both systole and diastole.", category: "Pediatrics/CHD", difficulty: 2 },
  { id: "rn-chd-overview-13", type: "question", question: "What is the 'egg-on-a-string' chest X-ray appearance associated with?", options: ["TOF", "Transposition of the Great Arteries (TGA)", "Coarctation", "VSD"], correctIndex: 1, answer: "Transposition of the Great Arteries produces an 'egg-on-a-string' silhouette: the egg-shaped heart (from the malpositioned great vessels creating a narrow mediastinal shadow) sits on a string-like vascular pedicle.", category: "Pediatrics/CHD", difficulty: 3 },
  { id: "rn-chd-overview-14", type: "question", question: "Why is subacute bacterial endocarditis (SBE) prophylaxis important in certain CHD patients?", options: ["Not needed for any CHD", "Turbulent blood flow from defects damages endocardium creating sites for bacterial colonization; antibiotics before dental procedures prevent endocarditis", "Only needed after repair", "Only for cyanotic lesions"], correctIndex: 1, answer: "AHA guidelines: SBE prophylaxis before dental procedures for unrepaired cyanotic CHD, repaired CHD with residual defects, prosthetic valves, or previous endocarditis. Amoxicillin 2 g PO (adults) or 50 mg/kg (children) 30-60 min before procedure.", category: "Pediatrics/CHD", difficulty: 2 },
  { id: "rn-chd-overview-15", type: "question", question: "What genetic syndrome is most associated with complete atrioventricular canal defect?", options: ["Turner syndrome", "Down syndrome (Trisomy 21) — approximately 40% of children with Down syndrome have CHD, most commonly AVCD", "Marfan syndrome", "Williams syndrome"], correctIndex: 1, answer: "Down syndrome (Trisomy 21) is strongly associated with complete atrioventricular canal defect (AVCD/AVSD) — occurs in approximately 20% of children with Down syndrome. All neonates with Down syndrome should have echocardiographic screening.", category: "Pediatrics/CHD", difficulty: 2 },
  { id: "rn-chd-overview-16", type: "question", question: "What dietary modification helps infants with CHD and heart failure?", options: ["Fluid restriction only", "Calorie-dense formula (24-30 kcal/oz) to maximize nutrition with minimal volume, as these infants tire easily during feeding", "Low-fat diet", "Soy formula only"], correctIndex: 1, answer: "Infants with CHD have increased metabolic demands but tire easily during feeding. Calorie-dense formula (concentrating formula or adding supplements to achieve 24-30 kcal/oz) provides adequate nutrition without excessive volume. Small, frequent feedings reduce metabolic demand.", category: "Pediatrics/CHD", difficulty: 2 },
  { id: "rn-chd-overview-17", type: "question", question: "What is polycythemia and why does it occur in cyanotic CHD?", options: ["Low RBC count", "Elevated red blood cell count — the body produces more RBCs to compensate for chronic hypoxemia, increasing oxygen-carrying capacity", "High white blood cell count", "Elevated platelet count"], correctIndex: 1, answer: "Chronic hypoxemia in cyanotic CHD stimulates erythropoietin production, increasing RBC mass (polycythemia). While compensatory, excessive polycythemia (Hct >65%) increases blood viscosity, raising risk for stroke and thrombosis.", category: "Pediatrics/CHD", difficulty: 2 },
  { id: "rn-chd-overview-18", type: "question", question: "What is the Fontan procedure?", options: ["VSD repair", "A palliative surgery for single-ventricle heart defects (e.g., HLHS, tricuspid atresia) that directs systemic venous blood to lungs without a pumping chamber", "Heart transplant", "PDA ligation"], correctIndex: 1, answer: "Fontan operation: final stage of single-ventricle palliation. Connects IVC directly to pulmonary arteries so systemic venous blood flows passively to lungs without a subpulmonary ventricle. Requires low pulmonary pressures. Preceded by Glenn shunt.", category: "Pediatrics/CHD", difficulty: 3 },
  { id: "rn-chd-overview-19", type: "question", question: "A neonate with TGA has severe cyanosis. What emergency procedure creates mixing of blood between atria?", options: ["VSD creation", "Balloon atrial septostomy (Rashkind procedure) — creates or enlarges the foramen ovale to allow mixing of oxygenated and deoxygenated blood", "Fontan procedure", "CTI ablation"], correctIndex: 1, answer: "Balloon atrial septostomy (Rashkind): catheter-based procedure to enlarge the atrial communication, allowing oxygenated pulmonary venous blood to mix with deoxygenated systemic venous blood. This improves oxygenation temporarily until arterial switch operation.", category: "Pediatrics/CHD", difficulty: 3 },
  { id: "rn-chd-overview-20", type: "question", question: "What is the difference between preductal and postductal coarctation?", options: ["No difference", "Preductal: narrowing before the ductus arteriosus (ductal-dependent, presents in neonates). Postductal: narrowing after the ductus (may present later with hypertension)", "Preductal is less severe", "Postductal occurs before the ductus"], correctIndex: 1, answer: "Preductal (infantile) coarctation: narrowing proximal to the ductus — ductal-dependent for lower body perfusion, presents early with cardiovascular collapse. Postductal (adult) coarctation: narrowing distal to ductus, presents later with upper body hypertension and collateral development.", category: "Pediatrics/CHD", difficulty: 3 },
  { id: "rn-chd-overview-21", type: "question", question: "What is the 'snowman sign' on chest X-ray associated with?", options: ["TOF", "Total anomalous pulmonary venous return (TAPVR) — supracardiac type", "Coarctation", "VSD"], correctIndex: 1, answer: "Supracardiac TAPVR produces a 'snowman' or 'figure-8' sign on CXR: the upper snowball represents dilated vertical vein and SVC, the lower snowball is the enlarged heart. Pulmonary veins drain abnormally to the right atrium instead of the left.", category: "Pediatrics/CHD", difficulty: 3 },
  { id: "rn-chd-overview-22", type: "question", question: "What is clubbing and what does it indicate in CHD?", options: ["A sport injury", "Enlargement and rounding of the fingertips/nailbeds from chronic hypoxemia — indicates long-standing cyanotic heart disease", "Normal nail variant", "Nutritional deficiency only"], correctIndex: 1, answer: "Digital clubbing (widened, bulbous fingertips with loss of nail angle) develops from chronic tissue hypoxia stimulating vascular proliferation. In CHD, it indicates long-standing cyanosis and should prompt evaluation for surgical correction if not already done.", category: "Pediatrics/CHD", difficulty: 2 },
  { id: "rn-chd-overview-23", type: "question", question: "What is the nurse's priority when a neonate with known CHD develops sudden cardiovascular collapse?", options: ["Obtain weight", "Assess for ductal closure — start PGE1 if ductal-dependent lesion, provide respiratory support, and prepare for emergency intervention", "Schedule echocardiogram for next week", "Observe for 6 hours"], correctIndex: 1, answer: "Sudden collapse in neonate with CHD: suspect ductal closure. Immediate PGE1, airway management (apnea risk from PGE1), IV access, fluid resuscitation, and cardiology/surgery notification. This is a life-threatening emergency requiring immediate intervention.", category: "Pediatrics/CHD", difficulty: 2 },
  { id: "rn-chd-overview-24", type: "question", question: "What is the role of echocardiography in CHD diagnosis?", options: ["Not useful for CHD", "Echocardiography is the primary diagnostic tool — provides detailed anatomical assessment, shunt quantification, and hemodynamic evaluation without radiation", "Only CXR is needed", "CT scan is first-line"], correctIndex: 1, answer: "Echocardiography is the gold standard for CHD diagnosis: visualizes structural defects, quantifies shunt direction/severity (Qp:Qs ratio), measures chamber sizes, evaluates valve function, and assesses hemodynamics. Non-invasive, no radiation, performed at bedside.", category: "Pediatrics/CHD", difficulty: 1 },
  { id: "rn-chd-overview-25", type: "question", question: "What psychosocial support should the nurse provide to parents of a child newly diagnosed with CHD?", options: ["No support needed", "Provide clear information about the diagnosis, connect with support groups, address parental anxiety, and coordinate care team communication", "Only give written materials", "Refer to psychiatry immediately"], correctIndex: 1, answer: "Nursing support: provide clear, age-appropriate education about the defect and treatment plan, address parental guilt and anxiety, connect with CHD support organizations, facilitate communication between cardiology/surgery teams and family, and assess family coping.", category: "Pediatrics/CHD", difficulty: 1 },

  // TETRALOGY OF FALLOT — 25 cards
  { id: "rn-chd-tof-1", type: "question", question: "Four anatomical defects in TOF?", options: ["ASD, PDA, coarctation, MS", "VSD, RVOT obstruction (pulmonary stenosis), overriding aorta, RV hypertrophy", "Tricuspid atresia, ASD, PDA, PS", "Transposition, truncus, VSD, ASD"], correctIndex: 1, answer: "TOF: (1) large VSD, (2) RVOT obstruction (pulmonary stenosis), (3) overriding aorta (over VSD), (4) RV hypertrophy (compensatory). Severity of RVOT obstruction determines degree of cyanosis.", category: "Pediatrics/CHD", difficulty: 2 },
  { id: "rn-chd-tof-2", type: "question", question: "What is a hypercyanotic (tet) spell?", options: ["Cardiac tamponade", "Acute severe cyanosis from dynamic infundibular spasm worsening RVOT obstruction and increasing R→L shunting", "Heart failure exacerbation", "Seizure"], correctIndex: 1, answer: "Tet spell: infundibular spasm worsens RVOT obstruction → dramatically increased R→L shunt → acute severe cyanosis, agitation, hyperpnea. Medical emergency requiring immediate intervention.", category: "Pediatrics/CHD", difficulty: 2 },
  { id: "rn-chd-tof-3", type: "question", question: "Immediate intervention during a tet spell?", options: ["Adenosine", "Knee-chest position to increase SVR and reduce R→L shunting", "IV potassium", "Ice packs"], correctIndex: 1, answer: "Knee-chest position: compresses femoral arteries, increases SVR, reduces R→L shunting, forces more blood through pulmonary circuit. Then: O2, calm infant, morphine (reduces spasm), phenylephrine IV if needed.", category: "Pediatrics/CHD", difficulty: 2 },
  { id: "rn-chd-tof-4", type: "question", question: "Why do TOF children squat during play?", options: ["Leg cramps", "Squatting increases SVR by trapping blood in legs, reducing R→L shunting and improving oxygenation", "Normal development", "Helps digestion"], correctIndex: 1, answer: "Squatting traps venous blood in lower extremities and compresses femoral arteries → increases SVR → reduces R→L shunt → improves pulmonary blood flow and oxygenation. Spontaneous equivalent of knee-chest positioning.", category: "Pediatrics/CHD", difficulty: 2 },
  { id: "rn-chd-tof-5", type: "question", question: "Classic CXR finding in TOF?", options: ["Cardiomegaly with congestion", "Boot-shaped heart (coeur en sabot) with decreased pulmonary vascular markings", "Egg-on-a-string", "Snowman sign"], correctIndex: 1, answer: "Boot-shaped heart from RV hypertrophy (upturned apex) + concave main PA segment. Decreased pulmonary markings from reduced pulmonary blood flow. Contrasts with L→R shunts (increased pulmonary markings).", category: "Pediatrics/CHD", difficulty: 3 },
  { id: "rn-chd-tof-6", type: "question", question: "Definitive surgical repair for TOF?", options: ["Heart transplant", "VSD patch closure + RVOT reconstruction, typically at 3-6 months", "Fontan", "Balloon valvuloplasty only"], correctIndex: 1, answer: "Complete repair: VSD patch closure + RVOT obstruction relief (muscle resection, transannular patch, or valve replacement). Ideally at 3-6 months. BT shunt may palliate unstable neonates until definitive repair.", category: "Pediatrics/CHD", difficulty: 3 },
  { id: "rn-chd-tof-7", type: "question", question: "What is a Blalock-Taussig (BT) shunt?", options: ["ASD repair", "Surgical connection between subclavian artery and pulmonary artery to increase pulmonary blood flow as palliation", "PDA ligation", "Fontan procedure"], correctIndex: 1, answer: "Modified BT shunt: Gore-Tex graft from subclavian to pulmonary artery to augment pulmonary blood flow. Palliative procedure for neonates too small/unstable for complete repair. Creates a continuous murmur. Monitor for shunt thrombosis.", category: "Pediatrics/CHD", difficulty: 3 },
  { id: "rn-chd-tof-8", type: "question", question: "What is the role of morphine during a tet spell?", options: ["Pain relief only", "Morphine relaxes the infundibular muscle spasm and reduces systemic venous return, decreasing R→L shunting", "Sedation only", "Increases HR"], correctIndex: 1, answer: "IV morphine 0.1 mg/kg during tet spells: relaxes infundibular smooth muscle (reducing dynamic RVOT obstruction), decreases preload, reduces agitation/oxygen demand, and reduces sympathetic drive that worsens the spasm.", category: "Pediatrics/CHD", difficulty: 3 },
  { id: "rn-chd-tof-9", type: "question", question: "What triggers tet spells?", options: ["Eating", "Crying, agitation, straining (Valsalva), dehydration, fever — anything that increases oxygen demand or decreases SVR", "Sleeping", "Cold weather only"], correctIndex: 1, answer: "Tet spell triggers: crying, agitation, pain, straining during defecation, dehydration, fever, exertion. These increase oxygen demand, decrease SVR, or trigger infundibular spasm — all worsen R→L shunting. Nurse should minimize crying/agitation.", category: "Pediatrics/CHD", difficulty: 2 },
  { id: "rn-chd-tof-10", type: "question", question: "What is the role of phenylephrine in tet spells?", options: ["Decreases SVR", "IV phenylephrine increases SVR (alpha-1 agonist), reducing the pressure gradient across the VSD and decreasing R→L shunting", "Bronchodilator", "Anti-arrhythmic"], correctIndex: 1, answer: "Phenylephrine is a pure alpha-1 agonist that raises SVR. In tet spells, increasing SVR reduces the pressure gradient favoring R→L shunt, forcing more blood through the RVOT into the pulmonary circulation. Used when knee-chest + morphine fail.", category: "Pediatrics/CHD", difficulty: 3 },
  { id: "rn-chd-tof-11", type: "question", question: "What is 'pink tet'?", options: ["A different disease", "TOF with minimal RVOT obstruction — enough pulmonary blood flow to prevent cyanosis at rest; may develop cyanosis with exercise or stress", "TOF after surgical repair", "Normal variant"], correctIndex: 1, answer: "Pink tet: acyanotic TOF with balanced hemodynamics (mild RVOT obstruction allows adequate pulmonary flow). Child appears pink at rest but may become cyanotic with exertion. May have predominantly L→R shunt through the VSD. Still needs eventual repair.", category: "Pediatrics/CHD", difficulty: 3 },
  { id: "rn-chd-tof-12", type: "question", question: "What is the most common cyanotic heart defect?", options: ["Transposition of great arteries", "Tetralogy of Fallot", "Tricuspid atresia", "Truncus arteriosus"], correctIndex: 1, answer: "Tetralogy of Fallot is the most common cyanotic congenital heart defect, accounting for approximately 10% of all CHD. It is the most common cyanotic lesion presenting beyond the newborn period.", category: "Pediatrics/CHD", difficulty: 1 },
  { id: "rn-chd-tof-13", type: "question", question: "What should the nurse monitor post-TOF repair?", options: ["Only temperature", "Arrhythmias (JET, heart block), bleeding, low cardiac output, residual VSD, pulmonary regurgitation, and neurological status", "Only wound healing", "Only urine output"], correctIndex: 1, answer: "Post-TOF repair monitoring: arrhythmias (JET most common, complete heart block from VSD patch near conduction system), bleeding (mediastinal drains), low cardiac output syndrome, residual VSD (new murmur), pulmonary regurgitation, and neurological assessment.", category: "Pediatrics/CHD", difficulty: 3 },
  { id: "rn-chd-tof-14", type: "question", question: "What long-term complication do TOF repair patients commonly develop?", options: ["No long-term issues", "Pulmonary regurgitation requiring pulmonary valve replacement later in life", "Immediate cure with no follow-up", "Only cosmetic scarring"], correctIndex: 1, answer: "After TOF repair, pulmonary regurgitation is very common (especially with transannular patch). Over decades, chronic PR causes RV dilation and dysfunction. Many patients eventually need pulmonary valve replacement (surgical or transcatheter) in adolescence/adulthood.", category: "Pediatrics/CHD", difficulty: 3 },
  { id: "rn-chd-tof-15", type: "question", question: "What iron supplementation teaching is important for infants with cyanotic CHD?", options: ["Iron is not important", "Iron is essential to maintain adequate hemoglobin for oxygen carrying — iron deficiency worsens relative anemia and can trigger tet spells", "Avoid all iron", "Iron causes cyanosis"], correctIndex: 1, answer: "Infants with cyanotic CHD depend on adequate hemoglobin for oxygen transport. Iron deficiency reduces RBC deformability and can trigger tet spells. Ensure adequate iron intake. Monitor ferritin and supplement as needed.", category: "Pediatrics/CHD", difficulty: 2 },
  { id: "rn-chd-tof-16", type: "question", question: "What is absent pulmonary valve syndrome variant of TOF?", options: ["Same as standard TOF", "TOF variant with rudimentary or absent pulmonary valve leaflets causing massive pulmonary regurgitation and dilated pulmonary arteries that compress the airways", "TOF without VSD", "ASD with PS"], correctIndex: 1, answer: "Absent pulmonary valve syndrome: rare TOF variant with no functional pulmonary valve. Results in massive PR with hugely dilated PAs that can compress tracheobronchial tree causing life-threatening airway obstruction. Requires early surgical intervention.", category: "Pediatrics/CHD", difficulty: 3 },
  { id: "rn-chd-tof-17", type: "question", question: "What is the murmur heard in TOF?", options: ["Continuous machinery murmur", "Systolic ejection murmur from RVOT obstruction best heard at left upper sternal border — murmur may decrease during tet spells (less flow)", "Diastolic rumble", "No murmur present"], correctIndex: 1, answer: "TOF murmur: systolic ejection murmur from RVOT obstruction at left upper sternal border. Paradoxically, murmur DECREASES or disappears during tet spells because less blood flows through the obstructed RVOT. Absence of murmur during cyanotic episode is ominous.", category: "Pediatrics/CHD", difficulty: 3 },
  { id: "rn-chd-tof-18", type: "question", question: "What cardiac catheterization finding confirms TOF diagnosis?", options: ["Normal pressures", "Equal systolic pressures in both ventricles (due to large VSD), demonstration of RVOT obstruction, and R→L shunt at ventricular level", "Left-to-right shunt only", "No shunt present"], correctIndex: 1, answer: "Catheterization shows equal RV and LV systolic pressures (due to nonrestrictive VSD), saturation step-down in aorta (R→L shunt), RVOT pressure gradient, and reduced pulmonary blood flow. However, echocardiography has largely replaced diagnostic catheterization.", category: "Pediatrics/CHD", difficulty: 3 },
  { id: "rn-chd-tof-19", type: "question", question: "What nursing intervention prevents tet spells during blood draws or procedures?", options: ["No prevention possible", "Allow parent to comfort, minimize crying time, use topical anesthetics, cluster care, and avoid unnecessary painful stimuli", "Sedate all children for blood draws", "Only draw blood under general anesthesia"], correctIndex: 1, answer: "Minimize agitation triggers: allow parental presence for comfort, use topical anesthetics (EMLA cream), cluster care activities, keep the environment calm, and ensure adequate hydration. If a tet spell begins during a procedure, stop immediately and position knee-chest.", category: "Pediatrics/CHD", difficulty: 2 },
  { id: "rn-chd-tof-20", type: "question", question: "What is the significance of 'tet physiology' in non-TOF cardiac lesions?", options: ["Only TOF has this physiology", "Any cardiac lesion with a VSD and dynamic RVOT obstruction can produce tet-like physiology with hypercyanotic episodes managed similarly", "Never occurs outside TOF", "Only occurs in adults"], correctIndex: 1, answer: "Tet physiology (VSD + dynamic RVOT obstruction → R→L shunt) can occur in other lesions: DORV with PS, single ventricle with PS, or even after partial TOF repair with residual RVOT obstruction. Management principles (increase SVR, reduce spasm) apply similarly.", category: "Pediatrics/CHD", difficulty: 3 },
  { id: "rn-chd-tof-21", type: "question", question: "What position should a TOF infant be placed in for feeding?", options: ["Flat on back", "Semi-upright position to reduce cardiac workload and monitor for signs of distress during feeds", "Prone position", "Trendelenburg"], correctIndex: 1, answer: "Feed in semi-upright/elevated position to reduce cardiac workload. Give small, frequent feedings. Monitor for feeding intolerance (diaphoresis, cyanosis, tachypnea, fatigue). Calorie-dense formula reduces volume needed. Allow rest breaks during feeds.", category: "Pediatrics/CHD", difficulty: 2 },
  { id: "rn-chd-tof-22", type: "question", question: "Why is propranolol sometimes prescribed for unrepaired TOF?", options: ["For hypertension", "Propranolol reduces heart rate and decreases dynamic RVOT obstruction, helping prevent tet spells", "For atrial fibrillation", "For pain management"], correctIndex: 1, answer: "Propranolol reduces HR, decreases dynamic infundibular spasm (beta-blockade reduces catecholamine-driven obstruction), and is used as prophylactic treatment to prevent tet spells while awaiting surgical repair.", category: "Pediatrics/CHD", difficulty: 3 },
  { id: "rn-chd-tof-23", type: "question", question: "What is the oxygen saturation typically seen in unrepaired TOF?", options: ["100%", "75-85% at baseline depending on severity of RVOT obstruction", "95-100% always", "Below 50%"], correctIndex: 1, answer: "Baseline SpO2 in unrepaired TOF varies with RVOT obstruction severity: mild obstruction (pink tet) may be >90%. Severe obstruction: 70-85%. During tet spells, SpO2 can drop dramatically to 40-60%. Individual baseline guides management decisions.", category: "Pediatrics/CHD", difficulty: 2 },
  { id: "rn-chd-tof-24", type: "question", question: "What discharge teaching is essential for parents of an infant with unrepaired TOF?", options: ["No special instructions", "Recognize tet spells (sudden deep cyanosis, irritability, limpness), place in knee-chest position, call 911, keep calm, and ensure adequate hydration", "Only return for scheduled appointments", "Avoid all physical activity"], correctIndex: 1, answer: "Parents must learn: tet spell recognition (sudden cyanosis, inconsolable crying, limpness), knee-chest position technique, when to call 911, keeping child calm, ensuring hydration, iron-rich diet, and scheduled follow-up before planned surgery.", category: "Pediatrics/CHD", difficulty: 2 },
  { id: "rn-chd-tof-25", type: "question", question: "What is the expected recovery timeline after complete TOF repair?", options: ["Immediate full recovery", "ICU stay 2-5 days, hospital stay 5-10 days, full recovery 4-6 weeks; lifelong cardiology follow-up needed for long-term complications", "1 day hospitalization", "Recovery takes years"], correctIndex: 1, answer: "Post-repair: ICU 2-5 days (monitoring for arrhythmias, low output), hospital 5-10 days, activity restriction 4-6 weeks. Lifelong cardiology follow-up: monitor for pulmonary regurgitation, RV function, arrhythmias, and need for reoperation.", category: "Pediatrics/CHD", difficulty: 2 },

  // SEPTAL DEFECTS VSD/ASD — 25 cards
  { id: "rn-chd-septal-1", type: "question", question: "Most common congenital heart defect?", options: ["TOF", "VSD", "ASD", "PDA"], correctIndex: 1, answer: "VSD is most common (25-30% of all CHD). Abnormal opening in interventricular septum. Small VSDs may close spontaneously; large VSDs cause hemodynamic compromise.", category: "Pediatrics/CHD", difficulty: 1 },
  { id: "rn-chd-septal-2", type: "question", question: "Characteristic VSD murmur?", options: ["Diastolic rumble", "Loud holosystolic murmur at left lower sternal border", "Continuous machinery", "Systolic click"], correctIndex: 1, answer: "VSD: harsh holosystolic (pansystolic) murmur at LLSB (3rd-4th ICS). Paradoxically, smaller VSDs produce louder murmurs (higher velocity flow through restrictive opening).", category: "Pediatrics/CHD", difficulty: 2 },
  { id: "rn-chd-septal-3", type: "question", question: "Hallmark ASD auscultatory finding?", options: ["Holosystolic murmur", "Fixed split S2 that does not vary with respiration", "Systolic click", "Diastolic rumble only"], correctIndex: 1, answer: "ASD: fixed splitting of S2 (doesn't vary with breathing). ASD equalizes atrial pressures, maintaining constant RV volume regardless of respiratory cycle. Also may hear systolic flow murmur at LUSB.", category: "Pediatrics/CHD", difficulty: 3 },
  { id: "rn-chd-septal-4", type: "question", question: "Hemodynamic consequence of large L→R shunt in VSD?", options: ["Systemic hypoxia", "Pulmonary overcirculation leading to volume overload and heart failure", "R→L shunting immediately", "Decreased pulmonary flow"], correctIndex: 1, answer: "Large VSD: excessive L→R shunt (systemic pressure > pulmonary pressure) → pulmonary overcirculation → increased pulmonary venous return → LA/LV volume overload → heart failure. Chronic overcirculation → pulmonary vascular remodeling.", category: "Pediatrics/CHD", difficulty: 2 },
  { id: "rn-chd-septal-5", type: "question", question: "Unrepaired large VSD with progressive cyanosis and clubbing indicates what?", options: ["Pneumonia", "Eisenmenger syndrome — irreversible shunt reversal", "Endocarditis", "Normal growth"], correctIndex: 1, answer: "Progressive cyanosis + clubbing in unrepaired large VSD = Eisenmenger syndrome. Irreversible pulmonary HTN has caused shunt reversal (R→L). Surgical closure now CONTRAINDICATED — would cause RV failure against fixed elevated pulmonary pressures.", category: "Pediatrics/CHD", difficulty: 3 },
  { id: "rn-chd-septal-6", type: "question", question: "How is transcatheter ASD closure performed?", options: ["Open-heart surgery only", "Device (Amplatzer occluder) deployed via femoral vein catheterization to seal the defect", "Medication only", "External compression"], correctIndex: 1, answer: "Secundum ASD: device closure via femoral vein. Amplatzer septal occluder opens on each side like an umbrella, sealing the defect. Avoids open-heart surgery, shorter recovery. Aspirin/clopidogrel for 6 months post-procedure.", category: "Pediatrics/CHD", difficulty: 3 },
  { id: "rn-chd-septal-7", type: "question", question: "What percentage of small VSDs close spontaneously?", options: ["0%", "Up to 80% of small muscular VSDs close spontaneously by age 2-3 years", "100% need surgery", "Only 5%"], correctIndex: 1, answer: "Up to 80% of small muscular VSDs close spontaneously within the first 2-3 years of life as the muscular septum grows. Small perimembranous VSDs also may close but less frequently. Serial echocardiography monitors for spontaneous closure.", category: "Pediatrics/CHD", difficulty: 2 },
  { id: "rn-chd-septal-8", type: "question", question: "When does a VSD require surgical repair?", options: ["All VSDs need immediate surgery", "Large VSDs causing heart failure, failure to thrive, or pulmonary hypertension unresponsive to medical management — ideally before age 1 year", "Never needs surgery", "Only at age 18"], correctIndex: 1, answer: "Surgical repair indications: large VSD with heart failure despite medical therapy, failure to thrive, Qp:Qs >2:1, or developing pulmonary hypertension. Repair before age 1 to prevent irreversible pulmonary vascular disease (Eisenmenger).", category: "Pediatrics/CHD", difficulty: 2 },
  { id: "rn-chd-septal-9", type: "question", question: "What is the Qp:Qs ratio and what does 2.5:1 mean?", options: ["Normal ratio", "2.5 times more blood flows to the pulmonary circuit than systemic — indicates hemodynamically significant L→R shunt requiring intervention", "Ratio of arterial to venous flow", "Measures cardiac output"], correctIndex: 1, answer: "Qp:Qs measures pulmonary-to-systemic blood flow ratio. Normal is 1:1. A ratio of 2.5:1 means 2.5x more blood goes through the lungs than systemic circulation. Ratio >2:1 generally indicates significant shunt requiring surgical intervention.", category: "Pediatrics/CHD", difficulty: 2 },
  { id: "rn-chd-septal-10", type: "question", question: "What are the three types of ASD?", options: ["Only one type exists", "Secundum (most common, 70%), primum (associated with AVCD/Down syndrome), and sinus venosus (near SVC/IVC junction)", "VSD types", "Only PFO"], correctIndex: 1, answer: "ASD types: Secundum (70%, central septum, amenable to device closure), Primum (lower septum, often with cleft mitral valve, associated with Down syndrome), Sinus venosus (near SVC or IVC, often with partial anomalous pulmonary venous return).", category: "Pediatrics/CHD", difficulty: 3 },
  { id: "rn-chd-septal-11", type: "question", question: "What is the difference between ASD and PFO?", options: ["Same thing", "PFO is a persistent fetal flap valve (25% of adults) that can allow R→L shunting under certain conditions; ASD is a true structural hole in the septum", "PFO is larger than ASD", "ASD is found only in infants"], correctIndex: 1, answer: "PFO is a residual fetal communication (flap valve) present in ~25% of adults. Usually functionally closed but can allow paradoxical embolism (stroke). ASD is a true structural defect. PFO closure indicated after cryptogenic stroke in young adults.", category: "Pediatrics/CHD", difficulty: 3 },
  { id: "rn-chd-septal-12", type: "question", question: "Why might a large ASD remain asymptomatic until adulthood?", options: ["It closes on its own", "L→R shunting causes gradual RV volume overload that is well-tolerated for years; symptoms (exercise intolerance, arrhythmias, paradoxical embolism) develop later", "Impossible to be asymptomatic", "Always symptomatic at birth"], correctIndex: 1, answer: "ASD often asymptomatic in childhood because the low-pressure L→R shunt is well-tolerated. Gradually, chronic RV volume overload causes RA/RV dilation, leading to symptoms in 30s-40s: exercise intolerance, atrial arrhythmias (AFib/flutter), and right heart failure.", category: "Pediatrics/CHD", difficulty: 2 },
  { id: "rn-chd-septal-13", type: "question", question: "What medications are used to manage heart failure from a large VSD while awaiting surgery?", options: ["No medications available", "Digoxin (improves contractility), furosemide (reduces volume overload), captopril (reduces afterload and L→R shunting)", "Beta-blockers only", "Aspirin only"], correctIndex: 1, answer: "Medical management: Digoxin (increases contractility), furosemide (reduces pulmonary congestion), ACE inhibitor like captopril (reduces afterload, decreasing L→R shunt magnitude). Calorie-dense feeds for failure to thrive. Medical management bridges to surgical repair.", category: "Pediatrics/CHD", difficulty: 2 },
  { id: "rn-chd-septal-14", type: "question", question: "What complication can occur after transcatheter ASD device closure?", options: ["Only minor bruising", "Device embolization, cardiac erosion/perforation, residual shunt, arrhythmias, or thrombus formation on the device", "No complications possible", "Only infection"], correctIndex: 1, answer: "Complications include: device embolization (dislodgement, may need surgical retrieval), cardiac erosion/perforation (rare but serious), residual shunt, new-onset arrhythmias, and thrombus on device (requires antiplatelet therapy). Monitor with serial echocardiography.", category: "Pediatrics/CHD", difficulty: 3 },
  { id: "rn-chd-septal-15", type: "question", question: "What is a paradoxical embolism and how is it related to septal defects?", options: ["Embolism in arteries only", "A venous thrombus (DVT) passes through an ASD or PFO to the systemic circulation (brain), causing stroke — bypasses the pulmonary filter", "Only occurs with PE", "Embolism from the left atrium"], correctIndex: 1, answer: "Paradoxical embolism: venous thrombus crosses through ASD/PFO (R→L shunting, especially with Valsalva/cough) into systemic circulation → stroke or systemic embolism. This is why PFO closure is considered after cryptogenic stroke in young adults.", category: "Pediatrics/CHD", difficulty: 3 },
  { id: "rn-chd-septal-16", type: "question", question: "What is the surgical approach for VSD repair?", options: ["Catheter-based always", "Median sternotomy with cardiopulmonary bypass; VSD closed with a Dacron or Gore-Tex patch or primary suture closure", "No surgery needed", "Thoracotomy only"], correctIndex: 1, answer: "VSD repair: median sternotomy, cardiopulmonary bypass, patch closure (Dacron/Gore-Tex) for large VSDs or primary suture for small VSDs. Approached through right atrium to avoid ventriculotomy. Risk of conduction system damage (heart block) near the VSD.", category: "Pediatrics/CHD", difficulty: 3 },
  { id: "rn-chd-septal-17", type: "question", question: "A child with VSD develops a new fever, splinter hemorrhages, and Janeway lesions. What should the nurse suspect?", options: ["Kawasaki disease", "Infective endocarditis — children with VSD are at increased risk due to turbulent flow across the defect", "Scarlet fever", "Normal childhood illness"], correctIndex: 1, answer: "Children with VSD have increased endocarditis risk from turbulent blood flow damaging the endocardium. Classic signs: fever, new/changing murmur, splinter hemorrhages, Janeway lesions (painless palms/soles), Osler nodes (painful fingertips). Blood cultures x3 and antibiotics.", category: "Pediatrics/CHD", difficulty: 3 },
  { id: "rn-chd-septal-18", type: "question", question: "What is a doubly committed VSD?", options: ["Two VSDs", "A VSD directly beneath both semilunar valves (aortic and pulmonary) — also called subarterial VSD; common in Asian populations, unlikely to close spontaneously", "VSD with ASD", "VSD in two locations"], correctIndex: 1, answer: "Doubly committed (subarterial/supracristal) VSD lies directly beneath the aortic and pulmonary valves. It does not close spontaneously and can cause progressive aortic regurgitation from prolapse of the right coronary cusp. Early surgical repair recommended.", category: "Pediatrics/CHD", difficulty: 3 },
  { id: "rn-chd-septal-19", type: "question", question: "How does the nurse assess for signs of pulmonary overcirculation in an infant with VSD?", options: ["Only check temperature", "Monitor for tachypnea, crackles on auscultation, hepatomegaly, poor weight gain, diaphoresis during feeds, and frequent respiratory infections", "Only check heart rate", "Only check blood pressure"], correctIndex: 1, answer: "Pulmonary overcirculation signs: tachypnea (most reliable early sign), crackles, hepatomegaly, failure to thrive, feeding diaphoresis, and recurrent respiratory infections (from pulmonary congestion). Serial weights and feeding assessment are key nursing interventions.", category: "Pediatrics/CHD", difficulty: 2 },
  { id: "rn-chd-septal-20", type: "question", question: "What happens to the VSD murmur as pulmonary hypertension develops?", options: ["Gets louder", "The murmur may become softer or disappear as the pressure gradient between ventricles equalizes — a quiet murmur with cyanosis is ominous", "Changes to diastolic", "No change"], correctIndex: 1, answer: "As pulmonary HTN develops, the pressure gradient across the VSD decreases, making the murmur softer or inaudible. A 'quiet' VSD with developing cyanosis suggests Eisenmenger transformation — an ominous sign. Loud P2 component develops.", category: "Pediatrics/CHD", difficulty: 3 },
  { id: "rn-chd-septal-21", type: "question", question: "What is the post-operative complication risk specific to VSD repair near the membranous septum?", options: ["No specific risk", "Complete heart block from injury to the AV node/bundle of His that runs along the inferior margin of membranous VSDs", "Pulmonary embolism", "Aortic stenosis"], correctIndex: 1, answer: "The AV node and bundle of His course along the posteroinferior rim of membranous VSDs. Surgical repair risks injuring these structures, causing transient or permanent complete heart block requiring permanent pacemaker (occurs in 1-2% of cases).", category: "Pediatrics/CHD", difficulty: 3 },
  { id: "rn-chd-septal-22", type: "question", question: "At what age should an unclosed ASD be repaired to prevent long-term complications?", options: ["Never if asymptomatic", "By age 3-5 years if significant shunting (Qp:Qs >1.5:1) to prevent RV dilation, arrhythmias, and paradoxical embolism", "Only after age 18", "At birth always"], correctIndex: 1, answer: "Significant ASD (Qp:Qs >1.5:1 with RV dilation) should ideally be closed by age 3-5. Earlier closure prevents long-term RV dysfunction, atrial arrhythmias, pulmonary HTN, and paradoxical embolism. Secundum ASDs are often closed by device; others need surgery.", category: "Pediatrics/CHD", difficulty: 2 },
  { id: "rn-chd-septal-23", type: "question", question: "What nursing assessment is important after surgical VSD repair?", options: ["Only pain assessment", "Monitor for heart block (widening PR, new bradycardia), residual shunt (new murmur), low cardiac output (poor perfusion, oliguria), and bleeding", "Only wound care", "Only temperature"], correctIndex: 1, answer: "Post-VSD repair assessment: continuous telemetry for heart block (PR prolongation, bradycardia), auscultation for new/residual murmur, assess perfusion (cap refill, pulses), urine output (>1 mL/kg/hr in children), chest drain output, wound assessment.", category: "Pediatrics/CHD", difficulty: 2 },
  { id: "rn-chd-septal-24", type: "question", question: "What is the relationship between VSD size and symptoms?", options: ["Small VSDs cause more symptoms", "Small restrictive VSDs are often asymptomatic with loud murmurs; large nonrestrictive VSDs cause heart failure with potentially softer murmurs", "All VSDs are equally symptomatic", "Size doesn't matter"], correctIndex: 1, answer: "Small restrictive VSDs: loud murmur (high-velocity jet), usually asymptomatic, may close spontaneously. Large nonrestrictive VSDs: free communication between ventricles, significant L→R shunt, heart failure, FTT, quieter murmur. Moderate VSDs: intermediate.", category: "Pediatrics/CHD", difficulty: 2 },
  { id: "rn-chd-septal-25", type: "question", question: "Why are recurrent respiratory infections common in infants with large VSDs?", options: ["Unrelated to VSD", "Pulmonary overcirculation causes pulmonary edema and congestion, creating a favorable environment for bacterial growth and impaired mucociliary clearance", "Due to medications only", "Only seen in adults"], correctIndex: 1, answer: "Excessive pulmonary blood flow causes interstitial pulmonary edema and congestion, impairing gas exchange and mucociliary clearance. The wet, congested lungs are prone to bacterial infections (pneumonia, bronchitis). Recurrent RTIs in infancy warrant cardiac evaluation.", category: "Pediatrics/CHD", difficulty: 2 },

  // COARCTATION OF THE AORTA — 25 cards
  { id: "rn-chd-coarct-1", type: "question", question: "Hallmark finding in coarctation of the aorta?", options: ["Central cyanosis", "BP higher in upper extremities than lower (>20 mmHg gradient), weak femoral pulses", "Irregular heart rhythm", "Absent heart sounds"], correctIndex: 1, answer: "Systolic BP gradient >20 mmHg upper > lower extremities + weak/absent femoral pulses with bounding upper extremity pulses. Check 4-extremity BPs in neonates.", category: "Pediatrics/CHD", difficulty: 2 },
  { id: "rn-chd-coarct-2", type: "question", question: "Critical coarctation in neonates depends on what structure?", options: ["Foramen ovale", "PDA providing blood flow to lower body", "Coronary arteries", "Umbilical vein"], correctIndex: 1, answer: "In critical preductal coarctation, PDA provides only pathway for blood to reach descending aorta. When ductus closes → acute cardiovascular collapse, absent femoral pulses, acidosis, shock. PGE1 must be started immediately.", category: "Pediatrics/CHD", difficulty: 3 },
  { id: "rn-chd-coarct-3", type: "question", question: "Genetic syndrome associated with coarctation?", options: ["Down syndrome", "Turner syndrome (45,X)", "Marfan", "Edwards syndrome"], correctIndex: 1, answer: "Turner syndrome (45,X): coarctation in ~10-15%, bicuspid aortic valve in ~30%. All Turner patients need cardiac screening. Other features: short stature, webbed neck, primary amenorrhea.", category: "Pediatrics/CHD", difficulty: 2 },
  { id: "rn-chd-coarct-4", type: "question", question: "Classic CXR finding in older children with coarctation?", options: ["Boot-shaped heart", "Rib notching from dilated collateral intercostal arteries", "Snowman sign", "Egg-on-a-string"], correctIndex: 1, answer: "Bilateral inferior rib notching visible after age 5-6 from enlarged collateral intercostal arteries bypassing the aortic narrowing. Scalloped rib margins on CXR. Also may see '3 sign' from pre/post stenotic dilation.", category: "Pediatrics/CHD", difficulty: 3 },
  { id: "rn-chd-coarct-5", type: "question", question: "Most important nursing assessment for suspected coarctation?", options: ["Blood glucose", "Simultaneous 4-extremity BPs and comparing brachial to femoral pulses", "Hearing screening", "Hip ultrasound"], correctIndex: 1, answer: "Compare right arm and lower extremity BPs/pulses. Gradient >20 mmHg (upper > lower) and weak/absent femoral pulses with bounding upper extremity pulses are diagnostic. All neonates: pre-discharge pulse oximetry screening.", category: "Pediatrics/CHD", difficulty: 2 },
  { id: "rn-chd-coarct-6", type: "question", question: "What is the '3 sign' or 'reverse 3 sign' seen in coarctation?", options: ["Normal CXR finding", "On CXR: the '3 sign' is formed by prestenotic dilation, the coarctation itself, and poststenotic dilation of the aorta; the 'reverse 3' or 'E sign' is seen on barium swallow", "Three ribs affected", "Three valve abnormalities"], correctIndex: 1, answer: "The '3 sign' on CXR: prestenotic proximal aortic dilation, the indentation of the coarctation, and poststenotic dilation create a '3' configuration. Barium swallow may show 'reverse 3' or 'E sign' from esophageal indentation by the abnormal aorta.", category: "Pediatrics/CHD", difficulty: 3 },
  { id: "rn-chd-coarct-7", type: "question", question: "What is the most common associated cardiac defect with coarctation?", options: ["ASD", "Bicuspid aortic valve (found in 50-85% of coarctation patients)", "PDA only", "VSD only"], correctIndex: 1, answer: "Bicuspid aortic valve (BAV) is found in 50-85% of coarctation patients. BAV can cause aortic stenosis or regurgitation over time. Other associations: VSD, mitral valve abnormalities, and intracranial aneurysms (Berry aneurysms in circle of Willis).", category: "Pediatrics/CHD", difficulty: 2 },
  { id: "rn-chd-coarct-8", type: "question", question: "What is post-coarctectomy syndrome?", options: ["Normal recovery", "Paradoxical hypertension and abdominal pain after coarctation repair, caused by sudden increased blood flow to previously hypoperfused mesenteric vessels", "Infection at surgical site", "Heart block after repair"], correctIndex: 1, answer: "Post-coarctectomy syndrome: paradoxical hypertension + severe abdominal pain 2-3 days after repair. Sudden restoration of pulsatile flow to mesenteric arteries causes arteritis. Treated with antihypertensives and bowel rest. Monitor for mesenteric vasculitis and necrotizing enterocolitis.", category: "Pediatrics/CHD", difficulty: 3 },
  { id: "rn-chd-coarct-9", type: "question", question: "What surgical options exist for coarctation repair?", options: ["Only medication management", "Resection with end-to-end anastomosis, subclavian flap aortoplasty, patch aortoplasty, or balloon angioplasty with stent placement", "Heart transplant only", "No treatment available"], correctIndex: 1, answer: "Surgical options: resection with end-to-end anastomosis (most common, removes narrowed segment), subclavian flap aortoplasty (uses subclavian artery to widen), extended end-to-end. Catheter-based: balloon angioplasty ± stent (native or recurrent coarctation in older children/adults).", category: "Pediatrics/CHD", difficulty: 3 },
  { id: "rn-chd-coarct-10", type: "question", question: "What long-term complication requires lifelong monitoring after coarctation repair?", options: ["No follow-up needed", "Recoarctation and persistent/recurrent hypertension — up to 30% develop late hypertension even after successful repair", "Only wound healing", "Only growth monitoring"], correctIndex: 1, answer: "Long-term issues: recoarctation (especially if repaired as neonate), persistent hypertension (up to 30% even after repair), aortic aneurysm at repair site, BAV complications, and berry aneurysms. Lifelong cardiology follow-up with BP monitoring and imaging required.", category: "Pediatrics/CHD", difficulty: 2 },
  { id: "rn-chd-coarct-11", type: "question", question: "Why might a neonate with coarctation appear normal initially?", options: ["Coarctation resolves spontaneously", "The PDA maintains lower body perfusion in utero and for the first few days of life — symptoms appear when the ductus closes", "Coarctation develops later", "The foramen ovale compensates"], correctIndex: 1, answer: "With PDA open, blood flows from aorta through the ductus to descending aorta, bypassing the coarctation. The neonate appears well. When ductus closes (typically day 1-5), lower body perfusion drops precipitously → cardiovascular collapse. This is why CCHD screening is vital.", category: "Pediatrics/CHD", difficulty: 2 },
  { id: "rn-chd-coarct-12", type: "question", question: "A child with coarctation complains of headaches, epistaxis, and leg claudication during exercise. What is the explanation?", options: ["Unrelated symptoms", "Upper body hypertension (headaches, epistaxis) from obstruction and lower body hypoperfusion (claudication) from reduced flow distal to coarctation", "Migraine disorder", "Iron deficiency"], correctIndex: 1, answer: "Classic presentation of undiagnosed coarctation in older children: upper body hypertension causes headaches and nosebleeds (epistaxis). Lower body receives reduced pulsatile flow → exercise-induced claudication and weakness in legs. Differential diagnosis for pediatric hypertension.", category: "Pediatrics/CHD", difficulty: 2 },
  { id: "rn-chd-coarct-13", type: "question", question: "How does coarctation affect cerebrovascular risk?", options: ["No cerebrovascular risk", "Upper body hypertension increases risk of intracranial aneurysm (Berry aneurysm) rupture and hemorrhagic stroke", "Only affects renal vessels", "Protects against stroke"], correctIndex: 1, answer: "Coarctation-related upper body hypertension increases risk of berry aneurysm formation in the circle of Willis. Rupture causes subarachnoid hemorrhage. Some centers screen for intracranial aneurysms. BP control is essential to reduce rupture risk.", category: "Pediatrics/CHD", difficulty: 3 },
  { id: "rn-chd-coarct-14", type: "question", question: "What is the role of balloon angioplasty in coarctation management?", options: ["First-line for neonates", "Primarily used for recurrent coarctation (recoarctation) after surgical repair, or for native coarctation in older children/adults with stent placement", "Never used for coarctation", "Only for PDA closure"], correctIndex: 1, answer: "Balloon angioplasty with stent: preferred for recoarctation after prior surgical repair. For native coarctation: stent placement in older children (>25 kg) and adults. Less effective in neonates due to small vessel size and elastic recoil. Surgical repair preferred in young infants.", category: "Pediatrics/CHD", difficulty: 3 },
  { id: "rn-chd-coarct-15", type: "question", question: "What is the pre-operative priority for a neonate with critical coarctation presenting in shock?", options: ["Immediate surgery", "Stabilize first: PGE1 to reopen PDA, correct acidosis, inotropic support, mechanical ventilation if needed, then proceed to surgery", "Observation only", "Antibiotics only"], correctIndex: 1, answer: "Stabilization before surgery: PGE1 infusion (maintain ductal patency), correct metabolic acidosis (NaHCO3), inotropic support (dopamine/milrinone), mechanical ventilation for respiratory failure, correct coagulopathy. Surgery once stabilized (usually within hours to days).", category: "Pediatrics/CHD", difficulty: 2 },
  { id: "rn-chd-coarct-16", type: "question", question: "What BP monitoring pattern should be followed after coarctation repair?", options: ["Annual BP check only", "Frequent BP monitoring in both upper and lower extremities to detect recoarctation (return of gradient) and persistent hypertension", "No monitoring needed after repair", "Only upper extremity BP"], correctIndex: 1, answer: "Post-repair: monitor BP in both arms and legs to detect recoarctation (return of upper-lower gradient >20 mmHg). Persistent hypertension common even after successful repair. Exercise stress testing may unmask exercise-induced hypertension. Lifelong cardiology follow-up.", category: "Pediatrics/CHD", difficulty: 2 },
  { id: "rn-chd-coarct-17", type: "question", question: "What activity restrictions apply to a child with coarctation?", options: ["No restrictions", "Before repair: avoid strenuous isometric exercise (weightlifting) due to hypertension risk; post-repair restrictions depend on residual findings", "Complete bed rest", "Only swimming allowed"], correctIndex: 1, answer: "Before repair: restrict strenuous isometric exercise (can cause dangerous BP spikes). After repair with no residual: gradual return to activities per cardiology guidance. If residual gradient, BAV, or aortic dilation: avoid competitive sports with high dynamic/static demand.", category: "Pediatrics/CHD", difficulty: 2 },
  { id: "rn-chd-coarct-18", type: "question", question: "Why are femoral pulses assessed in all newborn examinations?", options: ["To check for DVT", "Absent or weak femoral pulses may be the first sign of coarctation of the aorta — an important part of the newborn cardiovascular exam", "To assess hip dysplasia", "To check reflexes"], correctIndex: 1, answer: "Palpation of femoral pulses is a critical component of the newborn cardiovascular exam. Absent or weak femoral pulses compared to brachial pulses is the clinical hallmark of coarctation. This simple assessment can be lifesaving.", category: "Pediatrics/CHD", difficulty: 1 },
  { id: "rn-chd-coarct-19", type: "question", question: "What is the effect of coarctation on renal function?", options: ["No effect", "Reduced renal blood flow activates the renin-angiotensin-aldosterone system (RAAS), contributing to systemic hypertension", "Improves renal function", "Only affects liver"], correctIndex: 1, answer: "Reduced blood flow distal to coarctation causes renal hypoperfusion, activating RAAS → aldosterone secretion → sodium/water retention → worsening hypertension. This RAAS activation is a major contributor to persistent hypertension even after coarctation repair.", category: "Pediatrics/CHD", difficulty: 3 },
  { id: "rn-chd-coarct-20", type: "question", question: "What is interrupted aortic arch and how does it differ from coarctation?", options: ["Same condition", "Complete discontinuity of the aortic arch (no luminal continuity) vs coarctation (narrowing with some residual lumen) — interrupted arch is more severe and always ductal-dependent", "Less severe than coarctation", "Only occurs in adults"], correctIndex: 1, answer: "Interrupted aortic arch: complete discontinuity of the aortic arch (no blood flow continuity). More severe than coarctation. Always ductal-dependent — 100% lethal without PGE1 and surgical repair. Often associated with DiGeorge syndrome (22q11 deletion).", category: "Pediatrics/CHD", difficulty: 3 },
  { id: "rn-chd-coarct-21", type: "question", question: "What is the clinical significance of collateral circulation in coarctation?", options: ["Never develops", "Collateral vessels (intercostal, internal mammary) develop to bypass the narrowing — provide alternative blood flow but indicate chronic obstruction", "Indicates the coarctation has resolved", "Only develops after surgery"], correctIndex: 1, answer: "Collateral vessels develop over time to bypass the coarctation: dilated intercostal arteries (cause rib notching on CXR), internal mammary arteries, and other chest wall vessels. Presence indicates chronic obstruction and is typically seen in older children/adults with undiagnosed coarctation.", category: "Pediatrics/CHD", difficulty: 2 },
  { id: "rn-chd-coarct-22", type: "question", question: "What medications are used to manage hypertension after coarctation repair?", options: ["No medications needed", "ACE inhibitors, beta-blockers, or ARBs are commonly used for persistent post-repair hypertension", "Only diuretics", "Only calcium channel blockers"], correctIndex: 1, answer: "Post-repair hypertension: ACE inhibitors (enalapril) or ARBs are first-line (address RAAS activation). Beta-blockers also used. Goal: normalize BP to prevent long-term cardiovascular complications (LV hypertrophy, aneurysm, stroke). Lifestyle modifications also important.", category: "Pediatrics/CHD", difficulty: 2 },
  { id: "rn-chd-coarct-23", type: "question", question: "What imaging is used for long-term surveillance after coarctation repair?", options: ["No imaging needed", "MRI or CT angiography to monitor for recoarctation, aneurysm at repair site, and aortic arch morphology", "Only CXR", "Only echocardiogram"], correctIndex: 1, answer: "MRA or CTA provides detailed aortic arch imaging: detects recoarctation, aneurysm formation at the repair site, and assesses overall aortic morphology. Echocardiography monitors cardiac function and BAV. MRI preferred to avoid radiation in young patients. Serial imaging throughout life.", category: "Pediatrics/CHD", difficulty: 2 },
  { id: "rn-chd-coarct-24", type: "question", question: "A 16-year-old presents with severe hypertension, headaches, and diminished leg pulses. The diagnosis is coarctation. What is the preferred treatment?", options: ["Medication management only", "Transcatheter stent placement is often preferred for older children/adolescents with native coarctation", "No treatment needed at this age", "Heart transplant"], correctIndex: 1, answer: "For older children, adolescents, and adults with native coarctation, transcatheter balloon angioplasty with stent placement is increasingly preferred: less invasive, shorter recovery, excellent results. Surgery reserved for complex anatomy, long-segment coarctation, or associated lesions.", category: "Pediatrics/CHD", difficulty: 2 },
  { id: "rn-chd-coarct-25", type: "question", question: "What is subclavian steal phenomenon after subclavian flap aortoplasty for coarctation?", options: ["Normal finding", "The left subclavian artery is sacrificed in the repair, potentially causing left arm claudication and BP discrepancy between arms", "Stealing blood from the brain", "Right arm affected"], correctIndex: 1, answer: "Subclavian flap repair uses the left subclavian artery to patch the coarctation, sacrificing flow to the left arm. This may cause left arm shorter than right, reduced left arm BP, and claudication. Left arm BP is unreliable for monitoring — use right arm.", category: "Pediatrics/CHD", difficulty: 3 },

  // ANTICOAGULATION THERAPY — 25 cards
  { id: "rn-anticoag-therapy-1", type: "question", question: "Mechanism of UFH?", options: ["Inhibits vitamin K factors", "Potentiates antithrombin III, inactivating thrombin (IIa) and factor Xa", "Direct thrombin inhibitor", "Blocks platelet aggregation"], correctIndex: 1, answer: "UFH binds antithrombin III, accelerating inactivation of thrombin (IIa) and factor Xa by ~1000-fold. Short half-life (60-90 min), IV/SQ, monitored by aPTT (target 1.5-2.5x control).", category: "Pharmacology/Anticoagulation", difficulty: 2 },
  { id: "rn-anticoag-therapy-2", type: "question", question: "Lab monitoring for heparin?", options: ["INR", "aPTT (activated partial thromboplastin time)", "Platelet count only", "Fibrinogen"], correctIndex: 1, answer: "aPTT: therapeutic 1.5-2.5x control (~60-80 sec). Checked 6 hours after initiation or dose change. LMWH monitored by anti-Xa levels (if needed). INR monitors warfarin.", category: "Pharmacology/Anticoagulation", difficulty: 1 },
  { id: "rn-anticoag-therapy-3", type: "question", question: "How does warfarin work?", options: ["Direct thrombin inhibition", "Inhibits vitamin K epoxide reductase, blocking synthesis of factors II, VII, IX, X", "Activates antithrombin III", "Inhibits platelet adhesion"], correctIndex: 1, answer: "Warfarin blocks vitamin K recycling → prevents synthesis of vitamin K-dependent clotting factors (II, VII, IX, X) and proteins C, S. Full effect takes 3-5 days. Monitored by INR (target 2.0-3.0).", category: "Pharmacology/Anticoagulation", difficulty: 2 },
  { id: "rn-anticoag-therapy-4", type: "question", question: "Why overlap warfarin with heparin for 3-5 days?", options: ["Cost savings", "Warfarin takes 3-5 days for full anticoagulation; heparin bridges. Also, warfarin initially depletes protein C creating transient hypercoagulable state", "Same pathway", "No clinical reason"], correctIndex: 1, answer: "Warfarin depletes existing clotting factors over 3-5 days. Protein C is depleted first, creating a paradoxical transient hypercoagulable state. Heparin provides immediate anticoagulation during bridging. Continue heparin until INR therapeutic for ≥24 hours.", category: "Pharmacology/Anticoagulation", difficulty: 2 },
  { id: "rn-anticoag-therapy-5", type: "question", question: "Advantage of DOACs over warfarin?", options: ["Cheaper", "Predictable pharmacokinetics, fixed dosing, no routine monitoring, fewer drug-food interactions", "No bleeding risk", "Reversed by vitamin K"], correctIndex: 1, answer: "DOACs: predictable dose-response, no routine monitoring (no INR), fewer interactions (no vitamin K restrictions), rapid onset (2-4 hours vs 3-5 days). Disadvantages: shorter half-life requires adherence, higher cost, limited reversal agents.", category: "Pharmacology/Anticoagulation", difficulty: 2 },
  { id: "rn-anticoag-therapy-6", type: "question", question: "aPTT 95 seconds (therapeutic 60-80) on heparin. No active bleeding. What to do?", options: ["Continue infusion", "Stop heparin per protocol, notify provider, recheck aPTT as ordered", "Give protamine immediately", "Increase rate"], correctIndex: 1, answer: "Supratherapeutic aPTT = over-anticoagulation with bleeding risk. Stop infusion per weight-based protocol, notify provider, recheck aPTT in specified interval. Protamine reserved for active serious bleeding.", category: "Pharmacology/Anticoagulation", difficulty: 2 },
  { id: "rn-anticoag-therapy-7", type: "question", question: "Key difference between LMWH (enoxaparin) and UFH?", options: ["Identical", "LMWH: longer half-life, predictable PK, SQ dosing, usually no aPTT monitoring needed", "UFH is SQ only", "LMWH requires more monitoring"], correctIndex: 1, answer: "LMWH: longer half-life, predictable dose-response, weight-based SQ dosing, predominantly inhibits factor Xa, no routine aPTT. Monitor anti-Xa in obesity, renal failure, pregnancy. Partially reversible with protamine.", category: "Pharmacology/Anticoagulation", difficulty: 2 },
  { id: "rn-anticoag-therapy-8", type: "question", question: "Warfarin INR 6.2 with gingival bleeding. Treatment?", options: ["Continue warfarin", "Hold warfarin, IV vitamin K, consider 4-factor PCC if significant bleeding", "Protamine", "Idarucizumab"], correctIndex: 1, answer: "INR >5 with bleeding: hold warfarin, IV vitamin K 5-10 mg. For significant bleeding, 4-factor PCC provides immediate factor replacement. FFP is alternative. Protamine = heparin reversal. Idarucizumab = dabigatran reversal.", category: "Pharmacology/Anticoagulation", difficulty: 3 },
  { id: "rn-anticoag-therapy-9", type: "question", question: "Warfarin dietary teaching?", options: ["Avoid all green vegetables", "Maintain CONSISTENT vitamin K intake — don't dramatically increase or decrease", "Eat as much vitamin K as possible", "No modifications"], correctIndex: 1, answer: "CONSISTENCY is key. Sudden increase in vitamin K foods (spinach, kale, broccoli) decreases INR. Sudden decrease increases INR and bleeding risk. Don't eliminate vitamin K — maintain stable daily intake.", category: "Pharmacology/Anticoagulation", difficulty: 1 },
  { id: "rn-anticoag-therapy-10", type: "question", question: "Target INR for AFib/DVT on warfarin?", options: ["1.0-1.5", "2.0-3.0", "3.0-4.5", "4.0-5.0"], correctIndex: 1, answer: "Most indications (AFib, DVT, PE): INR 2.0-3.0. Mechanical mitral valve: 2.5-3.5. Below 2.0 = inadequate anticoagulation. Above 3.0 significantly increases bleeding risk. Check regularly (weekly initially, then monthly when stable).", category: "Pharmacology/Anticoagulation", difficulty: 1 },
  { id: "rn-anticoag-therapy-11", type: "question", question: "What is the mechanism of action of apixaban (Eliquis)?", options: ["Vitamin K antagonist", "Direct factor Xa inhibitor — selectively and reversibly blocks factor Xa, preventing thrombin generation", "Direct thrombin inhibitor", "Antithrombin III activator"], correctIndex: 1, answer: "Apixaban directly inhibits factor Xa (a key enzyme in the coagulation cascade that converts prothrombin to thrombin). Unlike warfarin, it targets a single factor with predictable pharmacokinetics. Oral, BID dosing, no monitoring required.", category: "Pharmacology/Anticoagulation", difficulty: 2 },
  { id: "rn-anticoag-therapy-12", type: "question", question: "What is the mechanism of dabigatran (Pradaxa)?", options: ["Factor Xa inhibitor", "Direct thrombin (factor IIa) inhibitor — directly binds and inhibits thrombin without needing antithrombin III", "Vitamin K antagonist", "Platelet inhibitor"], correctIndex: 1, answer: "Dabigatran is a direct thrombin (IIa) inhibitor that directly binds to thrombin's active site. Unlike heparin, it does not require antithrombin III as a cofactor. Oral, BID dosing. Only DOAC reversible by specific antidote (idarucizumab).", category: "Pharmacology/Anticoagulation", difficulty: 2 },
  { id: "rn-anticoag-therapy-13", type: "question", question: "LMWH in renal impairment (CrCl <30): what is the concern?", options: ["No concern", "LMWH is renally cleared — accumulation increases bleeding risk; reduce to once daily dosing or switch to UFH", "Double the dose", "Switch to aspirin"], correctIndex: 1, answer: "LMWH cleared by kidneys. In CrCl <30: enoxaparin dose reduced to 1 mg/kg ONCE daily (instead of BID), or switch to UFH (cleared by reticuloendothelial system). Monitor anti-Xa levels if continuing LMWH.", category: "Pharmacology/Anticoagulation", difficulty: 2 },
  { id: "rn-anticoag-therapy-14", type: "question", question: "What is heparin-induced thrombocytopenia (HIT) Type II?", options: ["Minor platelet drop", "Immune-mediated reaction: antibodies against heparin-PF4 complexes cause platelet activation and PARADOXICAL THROMBOSIS despite low platelets", "Viral infection", "Hemophilia"], correctIndex: 1, answer: "HIT Type II: IgG antibodies form against heparin-PF4 complexes → platelet activation → consumptive thrombocytopenia (>50% drop) + paradoxical hypercoagulable state (venous/arterial thrombosis). Occurs 5-10 days after heparin. ALL heparin must stop.", category: "Pharmacology/Anticoagulation", difficulty: 3 },
  { id: "rn-anticoag-therapy-15", type: "question", question: "A client on heparin for 7 days has platelet drop from 250K to 90K. What to suspect?", options: ["Normal variation", "HIT Type II", "Iron deficiency", "Dehydration"], correctIndex: 1, answer: ">50% platelet drop at days 5-10 of heparin = highly suspicious for HIT II. Calculate 4T score. Stop ALL heparin immediately (including flushes, coated lines). Start alternative anticoagulant (argatroban). Do NOT give warfarin until platelets recover.", category: "Pharmacology/Anticoagulation", difficulty: 3 },
  { id: "rn-anticoag-therapy-16", type: "question", question: "What is the weight-based heparin protocol?", options: ["One dose fits all", "Bolus of 80 units/kg followed by infusion at 18 units/kg/hr, with aPTT-based adjustments every 6 hours", "Fixed rate of 1000 units/hr", "Only SQ dosing"], correctIndex: 1, answer: "Weight-based dosing: bolus 80 units/kg IV, then 18 units/kg/hr infusion. aPTT checked at 6 hours, dose adjusted per institutional nomogram. More reliable than fixed-dose protocols for achieving therapeutic aPTT. Requires accurate patient weight.", category: "Pharmacology/Anticoagulation", difficulty: 2 },
  { id: "rn-anticoag-therapy-17", type: "question", question: "What DOAC-specific teaching should the nurse provide about missed doses of rivaroxaban?", options: ["Skip all doses for a week", "Take with the evening meal for the 20 mg dose; if missed, take as soon as remembered on the same day", "Take without food", "Double the next dose"], correctIndex: 1, answer: "Rivaroxaban 20 mg must be taken WITH FOOD (increases bioavailability by 39%). If missed, take as soon as remembered the same day. Unique among DOACs: once-daily dosing for AFib. For 15 mg BID (DVT treatment phase), both doses taken with food.", category: "Pharmacology/Anticoagulation", difficulty: 2 },
  { id: "rn-anticoag-therapy-18", type: "question", question: "What is bridge anticoagulation and when is it needed?", options: ["Never needed", "Short-acting anticoagulant (LMWH or UFH) used perioperatively when warfarin is held; needed for high-risk patients (mechanical valves, recent VTE)", "Switching between two oral drugs", "IV to oral conversion only"], correctIndex: 1, answer: "Bridge therapy: stopping warfarin 5 days before surgery and starting LMWH/UFH to maintain anticoagulation until procedure. Needed for high thrombotic risk (mechanical heart valve, recent VTE <3 months). DOACs usually don't need bridging (shorter half-life).", category: "Pharmacology/Anticoagulation", difficulty: 3 },
  { id: "rn-anticoag-therapy-19", type: "question", question: "What drugs interact with warfarin to increase bleeding risk?", options: ["Vitamin K supplements", "Antibiotics (metronidazole, fluconazole, TMP-SMX), amiodarone, NSAIDs, and many herbal supplements (ginkgo, garlic)", "ACE inhibitors only", "Statins only"], correctIndex: 1, answer: "Drugs that increase warfarin effect (increase INR/bleeding risk): antibiotics (inhibit gut vitamin K production), amiodarone (CYP inhibitor), NSAIDs (additive bleeding + GI erosion), SSRIs, acetaminophen (high doses). Ginkgo, garlic, ginger, dong quai also increase risk.", category: "Pharmacology/Anticoagulation", difficulty: 2 },
  { id: "rn-anticoag-therapy-20", type: "question", question: "What is the anti-Xa assay and when is it used?", options: ["Alternative to INR for warfarin", "Measures the anticoagulant effect of LMWH and factor Xa inhibitors; used in obesity, pregnancy, renal impairment, or extremes of body weight", "Measures platelet function", "Only for heparin monitoring"], correctIndex: 1, answer: "Anti-Xa level measures factor Xa inhibition. Used to monitor LMWH in special populations (obesity, renal failure, pregnancy, pediatrics). Also can monitor DOACs (apixaban, rivaroxaban) in emergencies. Not routinely needed for most LMWH or DOAC patients.", category: "Pharmacology/Anticoagulation", difficulty: 3 },
  { id: "rn-anticoag-therapy-21", type: "question", question: "A client on warfarin eats a large salad daily (consistent). Should the nurse be concerned?", options: ["Yes, all vitamin K must be avoided", "No — as long as vitamin K intake is CONSISTENT, the warfarin dose is adjusted accordingly; sudden changes are the problem, not consistent intake", "Must switch to DOAC", "Double the warfarin dose"], correctIndex: 1, answer: "Consistent vitamin K intake is perfectly acceptable on warfarin. The dose is titrated to achieve target INR at the patient's usual dietary pattern. Only CHANGES in vitamin K intake cause INR fluctuations. The key teaching: consistency, not avoidance.", category: "Pharmacology/Anticoagulation", difficulty: 2 },
  { id: "rn-anticoag-therapy-22", type: "question", question: "What is the nurse's priority when transitioning from heparin to warfarin?", options: ["Stop heparin when first warfarin dose is given", "Overlap both for minimum 5 days AND INR must be therapeutic (2.0-3.0) for ≥24 hours before stopping heparin", "Never overlap them", "Switch immediately"], correctIndex: 1, answer: "Bridge requirements: (1) minimum 5 days of overlap (warfarin takes this long to fully deplete clotting factors), AND (2) INR therapeutic ≥2.0 for ≥24 hours. Both criteria must be met before heparin discontinuation. Stopping heparin too early risks thrombosis.", category: "Pharmacology/Anticoagulation", difficulty: 2 },
  { id: "rn-anticoag-therapy-23", type: "question", question: "What is warfarin skin necrosis and when does it occur?", options: ["Common side effect at any time", "Rare complication occurring 3-8 days after initiation; protein C depletion creates localized thrombosis in subcutaneous vessels causing painful skin infarction", "Allergic rash", "Sun-related skin damage"], correctIndex: 1, answer: "Warfarin skin necrosis: occurs 3-8 days after starting warfarin, especially without heparin bridging. Protein C (anticoagulant, short half-life) is depleted before procoagulant factors, creating transient hypercoagulable state → microvascular thrombosis → skin necrosis (buttocks, thighs, breasts).", category: "Pharmacology/Anticoagulation", difficulty: 3 },
  { id: "rn-anticoag-therapy-24", type: "question", question: "What SQ injection technique does the nurse use for enoxaparin?", options: ["IM injection in deltoid", "SQ injection into abdominal fatty tissue, alternating sites, do NOT aspirate or massage after injection", "IV push only", "SQ in the thigh only"], correctIndex: 1, answer: "Enoxaparin SQ technique: inject into abdominal fatty tissue (2 inches from umbilicus), alternating left and right sides. Do NOT aspirate before injection. Do NOT rub or massage after injection (causes bruising). Leave the air bubble in the syringe as designed.", category: "Pharmacology/Anticoagulation", difficulty: 1 },
  { id: "rn-anticoag-therapy-25", type: "question", question: "What is the significance of CrCl (creatinine clearance) in DOAC prescribing?", options: ["Not important", "DOACs have varying degrees of renal clearance; dose adjustments or contraindications exist based on CrCl to prevent drug accumulation and bleeding", "Only affects warfarin", "Only for UFH dosing"], correctIndex: 1, answer: "Renal clearance varies: dabigatran (80% renal), rivaroxaban (33%), apixaban (27%), edoxaban (50%). Lower CrCl requires dose reduction or contraindication: dabigatran contraindicated if CrCl <30, apixaban dose-reduced with Cr ≥1.5 + age ≥80 or weight ≤60 kg. Monitor renal function annually.", category: "Pharmacology/Anticoagulation", difficulty: 3 },

  // BLEEDING RISKS & REVERSAL — 25 cards
  { id: "rn-anticoag-bleed-1", type: "question", question: "Heparin reversal agent?", options: ["Vitamin K", "Protamine sulfate", "Idarucizumab", "Andexanet alfa"], correctIndex: 1, answer: "Protamine: 1 mg per 100 units heparin given in preceding 2-3 hours. Max single dose: 50 mg. Slow IV (10 min) to avoid hypotension, bradycardia, anaphylactoid reaction. Partially reverses LMWH (~60%).", category: "Pharmacology/Anticoagulation", difficulty: 2 },
  { id: "rn-anticoag-bleed-2", type: "question", question: "What is idarucizumab (Praxbind)?", options: ["Reverses warfarin", "Monoclonal antibody fragment specifically reversing dabigatran (Pradaxa)", "Reverses all DOACs", "Reverses heparin"], correctIndex: 1, answer: "Idarucizumab: binds dabigatran with 350x greater affinity than thrombin, providing immediate complete reversal. Dose: 5 g IV (2 × 2.5 g vials). Reverses ONLY dabigatran, not other DOACs.", category: "Pharmacology/Anticoagulation", difficulty: 3 },
  { id: "rn-anticoag-bleed-3", type: "question", question: "What reverses factor Xa inhibitors (apixaban, rivaroxaban)?", options: ["Protamine", "Vitamin K", "Idarucizumab", "Andexanet alfa (Andexxa)"], correctIndex: 3, answer: "Andexanet alfa: recombinant modified factor Xa protein that acts as decoy receptor, binding Xa inhibitors. IV bolus + 2-hour infusion. Monitor for thromboembolic events post-reversal. If unavailable, 4-factor PCC is off-label alternative.", category: "Pharmacology/Anticoagulation", difficulty: 3 },
  { id: "rn-anticoag-bleed-4", type: "question", question: "What is HIT Type II?", options: ["Minor platelet decrease", "Immune-mediated: antibodies against heparin-PF4 cause platelet activation and paradoxical THROMBOSIS despite thrombocytopenia", "Viral infection", "Hemophilia"], correctIndex: 1, answer: "HIT II: IgG antibodies vs heparin-PF4 → platelet activation → thrombocytopenia + hypercoagulable state with thrombosis. Occurs days 5-10. Stop ALL heparin. Start argatroban. NO platelets (fuel thrombosis). NO warfarin until platelets >150K.", category: "Pharmacology/Anticoagulation", difficulty: 3 },
  { id: "rn-anticoag-bleed-5", type: "question", question: "Platelet drop 250K to 90K on day 7 of heparin. Immediate action?", options: ["Continue heparin", "Stop ALL heparin products immediately and notify provider", "Give extra heparin", "Give protamine"], correctIndex: 1, answer: ">50% platelet drop at days 5-10 = suspect HIT II. Stop ALL heparin (including flushes, coated catheters, LMWH). Send HIT antibodies/SRA. Start argatroban. Do NOT give platelets. Do NOT start warfarin.", category: "Pharmacology/Anticoagulation", difficulty: 3 },
  { id: "rn-anticoag-bleed-6", type: "question", question: "Anticoagulant bleeding precautions?", options: ["No precautions needed", "Soft toothbrush, electric razor, avoid IM injections, hold pressure 5+ min on venipuncture, fall prevention", "Restrict all activity", "Discontinue all meds"], correctIndex: 1, answer: "Bleeding precautions: soft toothbrush, electric razor, avoid IM injections, prolonged pressure on venipunctures (5+ min), fall prevention, stool softeners, avoid ASA/NSAIDs unless prescribed, monitor for occult bleeding (tarry stool, hematuria).", category: "Pharmacology/Anticoagulation", difficulty: 1 },
  { id: "rn-anticoag-bleed-7", type: "question", question: "Signs of internal bleeding in anticoagulated patients?", options: ["Elevated glucose", "Unexplained tachycardia, hypotension, melena, hemoptysis, hematuria, declining hemoglobin, petechiae, altered mental status", "Elevated temperature only", "Weight gain from edema"], correctIndex: 1, answer: "Internal bleeding signs: tachycardia (earliest), hypotension, dropping Hgb/Hct, melena/hematochezia, hemoptysis, hematuria, petechiae/ecchymoses, epistaxis, gingival bleeding, headache with neuro changes (ICH), abdominal/flank pain (retroperitoneal bleed).", category: "Pharmacology/Anticoagulation", difficulty: 2 },
  { id: "rn-anticoag-bleed-8", type: "question", question: "Alternative anticoagulant for HIT?", options: ["Different heparin brand", "Argatroban (direct thrombin inhibitor, no HIT antibody cross-reactivity)", "Warfarin immediately", "Aspirin"], correctIndex: 1, answer: "Argatroban: direct thrombin inhibitor, no HIT antibody cross-reactivity. Continuous IV infusion monitored by aPTT. Bivalirudin is another option. Warfarin CONTRAINDICATED initially in HIT (risk of skin necrosis/gangrene until platelets recover).", category: "Pharmacology/Anticoagulation", difficulty: 3 },
  { id: "rn-anticoag-bleed-9", type: "question", question: "What is the 4-factor PCC and when is it used?", options: ["A blood type", "Prothrombin complex concentrate containing factors II, VII, IX, X — used for urgent warfarin reversal and as off-label reversal for factor Xa inhibitors", "A coagulation test", "A type of FFP"], correctIndex: 1, answer: "4-factor PCC (Kcentra): contains concentrated factors II, VII, IX, X plus proteins C and S. Provides rapid INR reversal for warfarin within 15-30 minutes (vs hours for FFP/vitamin K alone). Off-label for Xa inhibitor reversal when andexanet alfa unavailable.", category: "Pharmacology/Anticoagulation", difficulty: 3 },
  { id: "rn-anticoag-bleed-10", type: "question", question: "How does protamine sulfate work to reverse heparin?", options: ["Blocks heparin receptors", "Protamine (positively charged) forms an ionic bond with heparin (negatively charged), creating a stable inactive complex", "Enhances heparin metabolism", "Destroys heparin in the liver"], correctIndex: 1, answer: "Protamine sulfate is a strongly positively charged protein that electrostatically binds to negatively charged heparin, forming a stable salt complex that neutralizes heparin's anticoagulant activity. Effect is immediate. The ionic binding is the mechanism.", category: "Pharmacology/Anticoagulation", difficulty: 3 },
  { id: "rn-anticoag-bleed-11", type: "question", question: "What allergic considerations exist with protamine sulfate?", options: ["No allergic risk", "Increased risk of allergic/anaphylactoid reactions in patients with fish allergy, prior protamine exposure, or vasectomized/infertile men (protamine is derived from fish sperm)", "Only latex allergy matters", "Only in children"], correctIndex: 1, answer: "Protamine is derived from salmon sperm. Increased anaphylactoid risk: prior protamine exposure, fish allergy, vasectomized/infertile men (may have anti-protamine antibodies). Administer slowly (over 10 min), have epinephrine available. Skin testing not reliable.", category: "Pharmacology/Anticoagulation", difficulty: 3 },
  { id: "rn-anticoag-bleed-12", type: "question", question: "What is the difference between vitamin K IV and oral for warfarin reversal?", options: ["No difference in speed", "IV vitamin K acts within 6-8 hours; oral vitamin K acts within 12-24 hours. IV has risk of anaphylactoid reaction and should be infused slowly", "Oral is faster", "IV is never used"], correctIndex: 1, answer: "IV vitamin K: onset 6-8 hours, use for serious bleeding or urgent reversal. Must infuse slowly (risk of anaphylaxis). Oral vitamin K: onset 12-24 hours, use for elevated INR without active bleeding. SQ absorption is erratic — avoid.", category: "Pharmacology/Anticoagulation", difficulty: 2 },
  { id: "rn-anticoag-bleed-13", type: "question", question: "A client on anticoagulation falls and hits their head. No visible injury. What is the nursing priority?", options: ["Apply ice and discharge", "Perform neurological assessment, notify provider, anticipate CT scan — intracranial hemorrhage can present delayed and is life-threatening on anticoagulants", "No assessment needed", "Give vitamin K prophylactically"], correctIndex: 1, answer: "Head trauma on anticoagulation is high-risk for intracranial hemorrhage, which may present with delayed symptoms. Immediate neuro assessment (GCS, pupils, motor), notify provider, CT head without contrast, close monitoring for 24 hours. Low threshold for imaging.", category: "Pharmacology/Anticoagulation", difficulty: 2 },
  { id: "rn-anticoag-bleed-14", type: "question", question: "When is activated charcoal useful for DOAC overdose?", options: ["Never useful", "Within 2 hours of ingestion — charcoal can reduce GI absorption of DOACs if given early", "After 24 hours", "Only for warfarin"], correctIndex: 1, answer: "Activated charcoal can reduce DOAC absorption if given within 2 hours of ingestion (up to 6 hours for some DOACs). Most effective within 1 hour. Not useful for heparin (IV) or warfarin taken chronically. Standard GI decontamination measure for acute OD.", category: "Pharmacology/Anticoagulation", difficulty: 2 },
  { id: "rn-anticoag-bleed-15", type: "question", question: "What is the HAS-BLED score component 'L' stand for?", options: ["Liver disease", "Labile INR — unstable INR with <60% of time in therapeutic range", "Leukemia", "Lactation"], correctIndex: 1, answer: "L = Labile INR: time in therapeutic range (TTR) <60% of the time. Indicates poor anticoagulation control, increasing both bleeding and thrombotic risk. Consider switching to a DOAC (which doesn't require INR monitoring) to eliminate this risk factor.", category: "Pharmacology/Anticoagulation", difficulty: 2 },
  { id: "rn-anticoag-bleed-16", type: "question", question: "What is the nurse's responsibility when a client on anticoagulation reports black tarry stools?", options: ["Normal finding", "Report immediately — melena indicates upper GI bleeding which is a serious complication of anticoagulation; assess vitals, hold anticoagulant, prepare for endoscopy", "Continue medications", "Only if lasting >1 week"], correctIndex: 1, answer: "Melena (black tarry stool) = upper GI bleeding, a potentially serious anticoagulation complication. Hold anticoagulant, assess vital signs (tachycardia, hypotension), check hemoglobin/hematocrit, type and screen, notify provider urgently, prepare for possible endoscopy.", category: "Pharmacology/Anticoagulation", difficulty: 2 },
  { id: "rn-anticoag-bleed-17", type: "question", question: "What preoperative anticoagulation management is needed before elective surgery?", options: ["Continue all anticoagulants through surgery", "Warfarin: stop 5 days pre-op (INR <1.5). DOACs: stop 24-48 hours pre-op based on renal function and bleeding risk. Bridge with LMWH if high thrombotic risk", "Stop anticoagulation 1 month before", "No changes needed"], correctIndex: 1, answer: "Perioperative anticoagulation: Warfarin stopped 5 days before (target INR <1.5). DOACs: 24-48 hours hold (longer for renal impairment). Bridge anticoagulation with LMWH for high-risk patients (mechanical valve, recent VTE). Resume post-op when hemostasis assured.", category: "Pharmacology/Anticoagulation", difficulty: 2 },
  { id: "rn-anticoag-bleed-18", type: "question", question: "What labs should be drawn before starting any anticoagulant?", options: ["Only CBC", "Baseline CBC (Hgb, Hct, platelets), PT/INR, aPTT, renal function (BUN, Cr), liver function, and pregnancy test in women of childbearing age", "Only BMP", "No baseline labs needed"], correctIndex: 1, answer: "Baseline labs: CBC (hemoglobin baseline for bleeding detection, platelet count), PT/INR (baseline coagulation), aPTT, BUN/Cr (renal function for dosing), LFTs (hepatic clearance), pregnancy test (warfarin is teratogenic). These establish baselines for monitoring.", category: "Pharmacology/Anticoagulation", difficulty: 2 },
  { id: "rn-anticoag-bleed-19", type: "question", question: "What is the reversal agent for edoxaban?", options: ["Idarucizumab", "No specific reversal agent approved; use 4-factor PCC as off-label reversal, or andexanet alfa (pending specific approval for edoxaban)", "Protamine", "Vitamin K"], correctIndex: 1, answer: "Edoxaban (factor Xa inhibitor) currently has no specifically approved reversal agent. Andexanet alfa reverses Xa inhibitors but approval may be limited to apixaban/rivaroxaban specifically. 4-factor PCC is the recommended off-label option. General supportive measures apply.", category: "Pharmacology/Anticoagulation", difficulty: 3 },
  { id: "rn-anticoag-bleed-20", type: "question", question: "A client with HIT develops DVT. Why is this NOT contradictory?", options: ["It is contradictory", "HIT is a PROthrombotic disorder despite the low platelet count — the activated platelets release prothrombotic microparticles, and clotting (not bleeding) is the primary risk", "DVT is unrelated to HIT", "HIT only causes bleeding"], correctIndex: 1, answer: "The paradox of HIT: thrombocytopenia occurs because platelets are being CONSUMED in thrombotic processes, not destroyed by bleeding. HIT antibodies activate platelets, generating thrombin and prothrombotic microparticles. The primary risk is thrombosis (50% if untreated), not hemorrhage.", category: "Pharmacology/Anticoagulation", difficulty: 3 },
  { id: "rn-anticoag-bleed-21", type: "question", question: "What is tranexamic acid (TXA) and when is it used alongside anticoagulation management?", options: ["An anticoagulant", "An antifibrinolytic that prevents clot breakdown; used as adjunct in severe bleeding to stabilize clots while reversing anticoagulation", "A thrombolytic", "A vitamin K supplement"], correctIndex: 1, answer: "Tranexamic acid inhibits plasminogen activation, preventing fibrinolysis (clot dissolution). Used as adjunct in severe hemorrhage: trauma, postpartum hemorrhage, surgical bleeding. Can help stabilize clots while anticoagulation is being reversed. Not a primary reversal agent.", category: "Pharmacology/Anticoagulation", difficulty: 3 },
  { id: "rn-anticoag-bleed-22", type: "question", question: "What is the nurse's role in anticoagulation stewardship?", options: ["Only give medications", "Verify correct drug/dose/indication, assess for contraindications, monitor labs, educate patients, recognize and report complications, and ensure safe transitions of care", "No specific role", "Only check INR"], correctIndex: 1, answer: "Anticoagulation stewardship nursing role: verify indication and correct drug/dose, assess contraindications (renal function, bleeding history, drug interactions), monitor labs per protocol, patient education (diet, bleeding signs, medication adherence), recognize complications, safe discharge/transitions.", category: "Pharmacology/Anticoagulation", difficulty: 1 },
  { id: "rn-anticoag-bleed-23", type: "question", question: "What are the components of the 4T scoring system for HIT?", options: ["Temperature, Tenderness, Timing, Treatment", "Thrombocytopenia severity, Timing of platelet fall, Thrombosis or other sequelae, oTher cause for thrombocytopenia ruled out", "Four different tests", "Therapeutic, Toxic, Therapeutic, Target"], correctIndex: 1, answer: "4T score for HIT probability: (1) Thrombocytopenia severity (% drop), (2) Timing of platelet fall (days 5-10), (3) Thrombosis or other sequelae, (4) oTher causes of thrombocytopenia ruled out. Score 0-3 = low probability, 4-5 = intermediate, 6-8 = high probability.", category: "Pharmacology/Anticoagulation", difficulty: 3 },
  { id: "rn-anticoag-bleed-24", type: "question", question: "Why should platelet transfusion be AVOIDED in HIT?", options: ["Platelets are too expensive", "Transfused platelets are activated by HIT antibodies, fueling MORE thrombosis — 'adding fuel to the fire'", "Platelets are not available for HIT patients", "No reason to avoid"], correctIndex: 1, answer: "In HIT, transfused platelets will be activated by the existing HIT antibodies, generating more thrombin and prothrombotic microparticles — worsening the thrombotic risk. Platelet transfusion in HIT is 'adding fuel to the fire.' Only transfuse if life-threatening hemorrhage.", category: "Pharmacology/Anticoagulation", difficulty: 3 },
  { id: "rn-anticoag-bleed-25", type: "question", question: "A client is discharged on warfarin. Which statement indicates correct understanding?", options: ["I will take ibuprofen for headaches", "I will maintain consistent vitamin K intake, use a soft toothbrush, report unusual bleeding, and keep regular INR appointments", "I will stop it when I feel better", "I can drink unlimited alcohol"], correctIndex: 1, answer: "Correct warfarin understanding: consistent vitamin K intake, soft toothbrush, electric razor, avoid NSAIDs, report bleeding (gums, urine, stool, bruises), regular INR monitoring, inform all providers, wear medical alert ID, avoid excessive alcohol.", category: "Pharmacology/Anticoagulation", difficulty: 1 },

  // DIC — 25 cards
  { id: "rn-anticoag-dic-1", type: "question", question: "What is the DIC paradox?", options: ["Only bleeding", "Simultaneous widespread clotting AND hemorrhage — consumptive coagulopathy depletes clotting factors and platelets", "Only thrombosis", "Only affects lungs"], correctIndex: 1, answer: "DIC: widespread microvascular thrombosis CONSUMES clotting factors, fibrinogen, and platelets → hemorrhage from depletion. Meanwhile, microthrombi cause end-organ ischemia. Called 'Death Is Coming.'", category: "Pharmacology/Anticoagulation", difficulty: 2 },
  { id: "rn-anticoag-dic-2", type: "question", question: "Most common DIC trigger?", options: ["Chronic hypertension", "Sepsis", "Osteoarthritis", "GERD"], correctIndex: 1, answer: "Sepsis is #1 trigger. Others: obstetric complications (abruption, amniotic fluid embolism, HELLP), major trauma, malignancy (acute promyelocytic leukemia), massive transfusion, burns, snake bites. Treatment: address underlying cause.", category: "Pharmacology/Anticoagulation", difficulty: 2 },
  { id: "rn-anticoag-dic-3", type: "question", question: "Classic DIC lab findings?", options: ["All normal", "Elevated D-dimer, elevated PT/aPTT, decreased fibrinogen, decreased platelets, schistocytes on smear", "Elevated Hgb/Hct", "Normal D-dimer with elevated platelets"], correctIndex: 1, answer: "DIC labs: markedly elevated D-dimer/FDPs, prolonged PT/aPTT, decreased fibrinogen (<100 mg/dL), thrombocytopenia, schistocytes (fragmented RBCs from fibrin strand shearing), elevated LDH.", category: "Pharmacology/Anticoagulation", difficulty: 2 },
  { id: "rn-anticoag-dic-4", type: "question", question: "Most important DIC treatment principle?", options: ["Heparin for all", "Identify and treat the underlying cause while providing supportive blood product replacement", "Surgery always", "Corticosteroids"], correctIndex: 1, answer: "Cornerstone: treat the CAUSE (antibiotics for sepsis, delivery for obstetric causes, chemotherapy for malignancy). Supportive: platelets if <10K or bleeding, cryoprecipitate for fibrinogen, FFP for factors, pRBCs for anemia.", category: "Pharmacology/Anticoagulation", difficulty: 2 },
  { id: "rn-anticoag-dic-5", type: "question", question: "D-dimer significance in DIC?", options: ["Always normal in DIC", "Elevated D-dimer = active fibrinolysis (breakdown of cross-linked fibrin). Normal D-dimer essentially rules out DIC", "Measures platelet function", "Only for PE diagnosis"], correctIndex: 1, answer: "D-dimer: fibrin degradation product formed when cross-linked fibrin is broken down by plasmin. In DIC, widespread thrombus formation + fibrinolysis → markedly elevated D-dimer. While nonspecific (elevated in many conditions), normal D-dimer essentially rules out DIC.", category: "Pharmacology/Anticoagulation", difficulty: 2 },
  { id: "rn-anticoag-dic-6", type: "question", question: "What are schistocytes and why present in DIC?", options: ["WBCs indicating infection", "Fragmented RBCs from mechanical shearing through fibrin strands in microvasculature (microangiopathic hemolytic anemia)", "Normal RBC variants", "Immature platelets"], correctIndex: 1, answer: "Schistocytes (helmet cells, fragments) form when RBCs are sheared passing through fibrin strands in microvessels. Their presence on blood smear supports DIC diagnosis and indicates active microvascular thrombosis.", category: "Pharmacology/Anticoagulation", difficulty: 3 },
  { id: "rn-anticoag-dic-7", type: "question", question: "Blood products for actively bleeding DIC?", options: ["Albumin only", "Platelets, FFP, cryoprecipitate, and pRBCs as indicated", "NS only", "Dextrose"], correctIndex: 1, answer: "Active DIC hemorrhage: platelets if <50K (or <10K without bleeding), cryoprecipitate for fibrinogen (target >100-150 mg/dL), FFP for clotting factors, pRBCs for anemia/hemorrhage. Monitor labs frequently.", category: "Pharmacology/Anticoagulation", difficulty: 2 },
  { id: "rn-anticoag-dic-8", type: "question", question: "Critical DIC nursing assessments?", options: ["Daily weight only", "Monitor for BOTH thrombotic and hemorrhagic complications: check body fluids for blood, assess perfusion, track serial coagulation labs", "RR only", "Temperature only"], correctIndex: 1, answer: "DIC assessments: check ALL body fluids for blood (urine, stool, sputum, wounds, NGT), petechiae/ecchymoses, neuro status (ICH), extremity perfusion (microthrombi), VS for hypovolemia, serial labs (PT, aPTT, fibrinogen, D-dimer, platelets, Hgb).", category: "Pharmacology/Anticoagulation", difficulty: 2 },
  { id: "rn-anticoag-dic-9", type: "question", question: "Why is cryoprecipitate specifically used in DIC?", options: ["Contains RBCs", "Rich in fibrinogen, factor VIII, XIII, and vWF — components consumed in DIC", "Lowers BP", "Treats infections"], correctIndex: 1, answer: "Cryoprecipitate: concentrated from FFP, rich in fibrinogen, factor VIII, factor XIII, vWF, and fibronectin. Efficiently replaces fibrinogen (each unit raises by ~5-10 mg/dL). Target fibrinogen >100-150 mg/dL in DIC.", category: "Pharmacology/Anticoagulation", difficulty: 3 },
  { id: "rn-anticoag-dic-10", type: "question", question: "Obstetric DIC from placental abruption: priority intervention?", options: ["Tocolytics", "Delivery of fetus and placenta to remove thromboplastin source", "Continue expectant management", "Heparin infusion"], correctIndex: 1, answer: "Placenta = source of tissue factor (thromboplastin) triggering coagulation cascade. Delivery removes the trigger = definitive treatment. Simultaneously: aggressive blood product resuscitation, hemodynamic support, monitor for postpartum hemorrhage.", category: "Pharmacology/Anticoagulation", difficulty: 3 },
  { id: "rn-anticoag-dic-11", type: "question", question: "What is the ISTH DIC scoring system?", options: ["A treatment protocol", "A diagnostic scoring tool using platelet count, D-dimer level, PT prolongation, and fibrinogen level to objectively diagnose DIC", "An imaging classification", "A surgical staging system"], correctIndex: 1, answer: "ISTH DIC score: assigns points based on platelet count (0-2), D-dimer (0-3), PT prolongation (0-2), and fibrinogen level (0-1). Score ≥5 = compatible with overt DIC. Serial scoring (q8-12h) tracks progression or improvement. Helps standardize diagnosis.", category: "Pharmacology/Anticoagulation", difficulty: 3 },
  { id: "rn-anticoag-dic-12", type: "question", question: "Why does DIC cause organ damage even without visible hemorrhage?", options: ["It doesn't cause organ damage", "Widespread microvascular thrombosis obstructs blood flow to organs (kidneys, lungs, brain, liver), causing ischemic injury even if external bleeding is not prominent", "Only external bleeding matters", "Organ damage is from medications only"], correctIndex: 1, answer: "Microthrombi in DIC occlude small vessels throughout the body, causing ischemic organ damage: renal failure (oliguria), ARDS (pulmonary microthrombi), hepatic dysfunction, altered mental status (cerebral microthrombi), and skin necrosis (purpura fulminans).", category: "Pharmacology/Anticoagulation", difficulty: 2 },
  { id: "rn-anticoag-dic-13", type: "question", question: "What is the role of heparin in DIC management?", options: ["Always contraindicated", "Controversial; may be considered in DIC with predominantly thrombotic features (purpura fulminans, acral ischemia) but contraindicated in hemorrhagic DIC", "First-line for all DIC", "Only for chronic DIC"], correctIndex: 1, answer: "Heparin in DIC is controversial. May help when thrombotic manifestations predominate (purpura fulminans, digital ischemia, venous thromboembolism). Contraindicated when hemorrhage is the primary feature. Decision is individualized. Low-dose UFH or prophylactic LMWH most commonly used.", category: "Pharmacology/Anticoagulation", difficulty: 3 },
  { id: "rn-anticoag-dic-14", type: "question", question: "What is purpura fulminans?", options: ["A mild rash", "Rapidly progressive purpura with skin necrosis from microvascular thrombosis and DIC — most commonly associated with meningococcemia or severe DIC", "An allergic reaction", "A vitamin deficiency"], correctIndex: 1, answer: "Purpura fulminans: rapidly progressive, symmetrical purpura with skin necrosis from extensive microvascular thrombosis and DIC. Most commonly seen with meningococcemia, but also with severe DIC from any cause. Requires aggressive DIC management and may need surgical debridement.", category: "Pharmacology/Anticoagulation", difficulty: 3 },
  { id: "rn-anticoag-dic-15", type: "question", question: "A client with DIC has a fibrinogen level of 48 mg/dL. How many units of cryoprecipitate are typically needed?", options: ["1 unit", "Approximately 10-20 units (each raises fibrinogen ~5-10 mg/dL) to achieve target >100-150 mg/dL", "100 units", "None needed"], correctIndex: 1, answer: "Target fibrinogen >100-150 mg/dL. Starting at 48 mg/dL, need to raise by ~50-100 mg/dL. Each unit of cryo raises fibrinogen ~5-10 mg/dL. Approximately 10-20 units needed (often given as 2-3 pooled doses of 5-10 units each). Recheck fibrinogen after infusion.", category: "Pharmacology/Anticoagulation", difficulty: 3 },
  { id: "rn-anticoag-dic-16", type: "question", question: "What is chronic (compensated) DIC?", options: ["Same as acute DIC", "A slower form where the body partially compensates by increasing clotting factor and platelet production; seen in malignancy", "DIC that resolved", "Chronic kidney disease"], correctIndex: 1, answer: "Chronic (compensated) DIC: slower activation of coagulation balanced by increased hepatic factor production and marrow platelet production. Labs may be near-normal or mildly abnormal. Seen with malignancy. May present with thrombosis rather than hemorrhage.", category: "Pharmacology/Anticoagulation", difficulty: 3 },
  { id: "rn-anticoag-dic-17", type: "question", question: "What are fibrin degradation products (FDPs) and how do they worsen DIC?", options: ["Helpful clotting factors", "FDPs are fragments from fibrin breakdown that act as anticoagulants — they inhibit thrombin, impair fibrin polymerization, and worsen bleeding", "Components that stop bleeding", "Red blood cell fragments"], correctIndex: 1, answer: "FDPs are fragments produced when plasmin breaks down fibrin/fibrinogen. They worsen DIC by: inhibiting thrombin, interfering with fibrin polymerization (preventing effective clot formation), and impairing platelet function. This creates a vicious cycle of more bleeding.", category: "Pharmacology/Anticoagulation", difficulty: 3 },
  { id: "rn-anticoag-dic-18", type: "question", question: "A septic patient develops DIC. The nurse notices decreased urine output and rising creatinine. What does this indicate?", options: ["Normal in sepsis", "Renal microvascular thrombosis from DIC causing acute kidney injury — may need renal replacement therapy", "Dehydration only", "Urinary tract infection"], correctIndex: 1, answer: "Renal microvascular thrombosis is a common organ consequence of DIC. Microthrombi occlude glomerular capillaries → AKI (oliguria, rising Cr/BUN). May require RRT (dialysis). Improving DIC by treating the underlying cause is essential for renal recovery.", category: "Pharmacology/Anticoagulation", difficulty: 2 },
  { id: "rn-anticoag-dic-19", type: "question", question: "What differentiates DIC from thrombotic thrombocytopenic purpura (TTP)?", options: ["Same condition", "DIC: low fibrinogen, elevated PT/aPTT, triggered by sepsis/trauma. TTP: normal fibrinogen and PT/aPTT, ADAMTS13 deficiency, pentad (thrombocytopenia, MAHA, neuro changes, fever, renal)", "Only age difference", "Only gender difference"], correctIndex: 1, answer: "Key differences: DIC has consumed fibrinogen (low) and prolonged PT/aPTT. TTP has normal fibrinogen and normal PT/aPTT. Both have schistocytes and thrombocytopenia. TTP is treated with plasma exchange (NOT the same as DIC treatment). ADAMTS13 level helps distinguish.", category: "Pharmacology/Anticoagulation", difficulty: 3 },
  { id: "rn-anticoag-dic-20", type: "question", question: "What is the nurse's priority intervention when DIC is suspected?", options: ["Wait for labs before acting", "Notify the provider immediately, obtain STAT coagulation labs (PT, aPTT, fibrinogen, D-dimer, CBC), type and screen for blood products, and assess for active bleeding and organ perfusion", "Give aspirin", "Apply warm compresses"], correctIndex: 1, answer: "When DIC is suspected: immediate provider notification, STAT labs (PT, aPTT, fibrinogen, D-dimer, CBC, blood smear for schistocytes), type and screen, assess all body fluids for blood, assess organ perfusion (neuro, renal, extremities), establish large-bore IV access.", category: "Pharmacology/Anticoagulation", difficulty: 2 },
  { id: "rn-anticoag-dic-21", type: "question", question: "How does amniotic fluid embolism cause DIC?", options: ["Through infection", "Amniotic fluid containing tissue factor and fetal antigens enters maternal circulation, triggering massive coagulation cascade activation and anaphylactoid reaction", "Through hemorrhage only", "Only causes respiratory failure"], correctIndex: 1, answer: "Amniotic fluid embolism: amniotic fluid (rich in tissue factor, fetal cells, vernix) enters maternal circulation → massive activation of coagulation cascade → consumptive coagulopathy (DIC). Also causes anaphylactoid reaction with cardiovascular collapse and respiratory failure. Mortality 20-60%.", category: "Pharmacology/Anticoagulation", difficulty: 3 },
  { id: "rn-anticoag-dic-22", type: "question", question: "What is the expected fibrinogen trend in improving DIC?", options: ["Continues to drop", "Fibrinogen levels rise as the underlying cause is treated and consumption decreases — an improving fibrinogen is a positive prognostic indicator", "Stays at zero", "Becomes unmeasurable"], correctIndex: 1, answer: "Rising fibrinogen = improving DIC. As the underlying cause is controlled, consumption decreases and the liver resumes fibrinogen production. Trending fibrinogen (q6-8h initially) helps assess response to treatment. Persistently low fibrinogen suggests ongoing consumption.", category: "Pharmacology/Anticoagulation", difficulty: 2 },
  { id: "rn-anticoag-dic-23", type: "question", question: "Why should the nurse minimize venipunctures in DIC patients?", options: ["Not important", "Each puncture site can become a source of uncontrolled bleeding due to depleted clotting factors and platelets; use existing lines and consolidate blood draws", "To save time", "Only to reduce pain"], correctIndex: 1, answer: "DIC patients have severely depleted clotting factors and platelets. Every venipuncture site is a potential uncontrolled hemorrhage source. Use existing IV/central lines for blood draws, consolidate labs into single draws, apply prolonged pressure (10+ min) to any puncture site.", category: "Pharmacology/Anticoagulation", difficulty: 2 },
  { id: "rn-anticoag-dic-24", type: "question", question: "A client with acute promyelocytic leukemia develops DIC. What specific chemotherapy agent treats both the leukemia and the DIC?", options: ["Doxorubicin", "All-trans retinoic acid (ATRA) — induces differentiation of malignant promyelocytes, stopping release of procoagulant granules", "Cisplatin", "Methotrexate"], correctIndex: 1, answer: "ATRA induces terminal differentiation of malignant promyelocytes into mature granulocytes, stopping the release of procoagulant granules (tissue factor, cancer procoagulant) that trigger DIC. ATRA treats the root cause of APL-associated DIC. Arsenic trioxide also used.", category: "Pharmacology/Anticoagulation", difficulty: 3 },
  { id: "rn-anticoag-dic-25", type: "question", question: "What massive transfusion protocol considerations apply in DIC?", options: ["Only give pRBCs", "Balanced resuscitation with 1:1:1 ratio (pRBCs:FFP:platelets) to avoid dilutional coagulopathy; also give cryoprecipitate for fibrinogen replacement; monitor calcium (citrate toxicity)", "No protocol needed", "Only crystalloids"], correctIndex: 1, answer: "Massive transfusion in DIC: balanced 1:1:1 ratio (pRBCs:FFP:platelets) prevents dilutional coagulopathy. Cryoprecipitate for fibrinogen. Monitor ionized calcium (citrate in blood products chelates calcium → hypocalcemia → worsens coagulopathy). Watch for hypothermia (use blood warmers).", category: "Pharmacology/Anticoagulation", difficulty: 3 },
];
